const LangContext = createContext(null);

function tFn(lang, key, vars) {
  const dict = TRANSLATIONS[lang] || TRANSLATIONS.en;
  let str = dict[key] !== undefined ? dict[key] : (TRANSLATIONS.en[key] !== undefined ? TRANSLATIONS.en[key] : key);
  if (vars) {
    Object.keys(vars).forEach(k => { str = str.split(`{${k}}`).join(vars[k]); });
  }
  return str;
}

function useT() {
  return useContext(LangContext);
}

/* ============================= HELPERS ============================= */
function nextPow2(n) { let p = 1; while (p < n) p *= 2; return p; }

function shuffle(arr) {
  const a = [...arr];
  for (let i = a.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [a[i], a[j]] = [a[j], a[i]];
  }
  return a;
}

function roundNameKey(playersInRound) {
  if (playersInRound === 2) return { kind: 'final' };
  if (playersInRound === 4) return { kind: 'semifinal' };
  if (playersInRound === 8) return { kind: 'quarterfinal' };
  return { kind: 'round_of', n: playersInRound };
}

function roundLabel(nameKey, t) {
  if (nameKey.kind === 'final') return t('round_final');
  if (nameKey.kind === 'semifinal') return t('round_semifinal');
  if (nameKey.kind === 'quarterfinal') return t('round_quarterfinal');
  return t('round_of', { n: nameKey.n });
}

function isSetWon(a, b) { return (a >= 11 || b >= 11) && Math.abs(a - b) >= 2; }
function majority(bestOf) { return Math.floor(bestOf / 2) + 1; }

function sumPoints(sets) {
  return sets.reduce((acc, s) => [acc[0] + s.a, acc[1] + s.b], [0, 0]);
}

function finalizeNames(names, mode, t) {
  if (mode === 'dubbel') {
    const finalNames = [];
    const pairMap = {};
    names.forEach((pair, i) => {
      const raw1 = pair && typeof pair === 'object' ? pair.p1 : '';
      const raw2 = pair && typeof pair === 'object' ? pair.p2 : '';
      const p1 = (raw1 && raw1.trim()) ? raw1.trim() : t('placeholder_player', { n: i * 2 + 1 });
      const p2 = (raw2 && raw2.trim()) ? raw2.trim() : t('placeholder_player', { n: i * 2 + 2 });
      const display = `${p1} & ${p2}`;
      finalNames.push(display);
      pairMap[display] = [p1, p2];
    });
    return { finalNames, pairMap };
  }
  const finalNames = names.map((n, i) => (n && n.trim()) ? n.trim() : t('placeholder_player', { n: i + 1 }));
  return { finalNames, pairMap: null };
}

function photoKey(name) {
  const safe = name.normalize('NFKD').replace(/[^a-zA-Z0-9]/g, '_').slice(0, 100);
  return `photo_${safe || 'x'}`;
}

function dataUrlToBlob(dataUrl) {
  const [header, base64] = dataUrl.split(',');
  const mimeMatch = header.match(/data:(.*?);base64/);
  const mime = mimeMatch ? mimeMatch[1] : 'image/jpeg';
  const binary = atob(base64);
  const bytes = new Uint8Array(binary.length);
  for (let i = 0; i < binary.length; i++) bytes[i] = binary.charCodeAt(i);
  return new Blob([bytes], { type: mime });
}

function resizeImage(file, maxSize = 240) {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = (e) => {
      const img = new Image();
      img.onload = () => {
        let { width, height } = img;
        if (width > height) { if (width > maxSize) { height = Math.round(height * maxSize / width); width = maxSize; } }
        else { if (height > maxSize) { width = Math.round(width * maxSize / height); height = maxSize; } }
        const canvas = document.createElement('canvas');
        canvas.width = width; canvas.height = height;
        const ctx = canvas.getContext('2d');
        ctx.drawImage(img, 0, 0, width, height);
        resolve(canvas.toDataURL('image/jpeg', 0.85));
      };
      img.onerror = reject;
      img.src = e.target.result;
    };
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
}

/* Quarterfinal, semifinal and final are always best of 7 (4 winning sets). Earlier rounds are best of 5. */
function generateBracket(entries) {
  const size = nextPow2(entries.length);
  const shuffled = shuffle(entries);
  const slots = [...shuffled];
  while (slots.length < size) slots.push(null);
  const numRounds = Math.log2(size);
  const rounds = [];
  for (let r = 0; r < numRounds; r++) {
    const matchCount = size / Math.pow(2, r + 1);
    const playersInRound = matchCount * 2;
    const bestOf = playersInRound <= 8 ? 7 : 5;
    const matches = [];
    for (let m = 0; m < matchCount; m++) {
      matches.push({
        id: `r${r}m${m}`,
        p1: r === 0 ? slots[2 * m] : null,
        p2: r === 0 ? slots[2 * m + 1] : null,
        winner: null,
        score: null,
        bestOf,
      });
    }
    rounds.push({ nameKey: roundNameKey(playersInRound), bestOf, matches });
  }
  if (rounds.length > 0) {
    rounds[0].matches.forEach((match, i) => {
      if ((match.p1 === null) !== (match.p2 === null)) {
        match.winner = match.p1 || match.p2;
        match.score = 'bye';
        if (rounds.length > 1) {
          const nextIndex = Math.floor(i / 2);
          const slotKey = i % 2 === 0 ? 'p1' : 'p2';
          rounds[1].matches[nextIndex][slotKey] = match.winner;
        }
      }
    });
  }
  return rounds;
}

function recordBracketResult(rounds, roundIdx, matchIdx, winner, score) {
  const newRounds = rounds.map(r => ({ ...r, matches: r.matches.map(m => ({ ...m })) }));
  newRounds[roundIdx].matches[matchIdx].winner = winner;
  newRounds[roundIdx].matches[matchIdx].score = score;
  if (roundIdx + 1 < newRounds.length) {
    const nextIndex = Math.floor(matchIdx / 2);
    const slotKey = matchIdx % 2 === 0 ? 'p1' : 'p2';
    newRounds[roundIdx + 1].matches[nextIndex][slotKey] = winner;
  }
  return newRounds;
}

function generateRoundRobin(entries) {
  const matches = [];
  for (let i = 0; i < entries.length; i++) {
    for (let j = i + 1; j < entries.length; j++) {
      matches.push({ id: `m${i}-${j}`, p1: entries[i], p2: entries[j], winner: null, score: null });
    }
  }
  return matches;
}

function computeStandings(entries, matches) {
  const stats = {};
  entries.forEach(e => { stats[e] = { name: e, w: 0, l: 0, setsFor: 0, setsAgainst: 0 }; });
  matches.forEach(m => {
    if (!m.winner) return;
    const loser = m.winner === m.p1 ? m.p2 : m.p1;
    stats[m.winner].w++;
    stats[loser].l++;
    if (m.score) {
      stats[m.p1].setsFor += m.score.setsA;
      stats[m.p1].setsAgainst += m.score.setsB;
      stats[m.p2].setsFor += m.score.setsB;
      stats[m.p2].setsAgainst += m.score.setsA;
    }
  });
  return Object.values(stats).sort((a, b) => b.w - a.w || (b.setsFor - b.setsAgainst) - (a.setsFor - a.setsAgainst));
}

function aggregateStats(matchLog) {
  const stats = {};
  function ensure(n) { if (!stats[n]) stats[n] = { name: n, played: 0, w: 0, l: 0, setsFor: 0, setsAgainst: 0, pointsFor: 0, pointsAgainst: 0 }; return stats[n]; }
  matchLog.forEach(m => {
    const a = ensure(m.nameA), b = ensure(m.nameB);
    a.played++; b.played++;
    a.setsFor += m.setsA; a.setsAgainst += m.setsB;
    b.setsFor += m.setsB; b.setsAgainst += m.setsA;
    a.pointsFor += (m.totalPointsA || 0); a.pointsAgainst += (m.totalPointsB || 0);
    b.pointsFor += (m.totalPointsB || 0); b.pointsAgainst += (m.totalPointsA || 0);
    if (m.winner === m.nameA) { a.w++; b.l++; } else { b.w++; a.l++; }
  });
  return Object.values(stats).sort((x, y) => y.w - x.w || (y.setsFor - y.setsAgainst) - (x.setsFor - x.setsAgainst));
}

/* pointLog entries: [side(0=a,1=b), server(0=a,1=b), aScoreAfter, bScoreAfter, setIndex] */
function computeServeStats(pointLog) {
  let aServePts = 0, aServeWon = 0, bServePts = 0, bServeWon = 0;
  (pointLog || []).forEach(([side, srv]) => {
    if (srv === 0) { aServePts++; if (side === 0) aServeWon++; }
    else { bServePts++; if (side === 1) bServeWon++; }
  });
  return {
    a: { servePts: aServePts, serveWon: aServeWon, returnPts: bServePts, returnWon: bServePts - bServeWon },
    b: { servePts: bServePts, serveWon: bServeWon, returnPts: aServePts, returnWon: aServePts - aServeWon },
  };
}

function aggregateServeStats(matchLog, playerName) {
  let servePts = 0, serveWon = 0, returnPts = 0, returnWon = 0;
  matchLog.forEach(m => {
    if (!m.pointLog || !m.pointLog.length) return;
    const isA = m.nameA === playerName, isB = m.nameB === playerName;
    if (!isA && !isB) return;
    const s = computeServeStats(m.pointLog);
    const mine = isA ? s.a : s.b;
    servePts += mine.servePts; serveWon += mine.serveWon;
    returnPts += mine.returnPts; returnWon += mine.returnWon;
  });
  return { servePts, serveWon, returnPts, returnWon };
}

