const TIER_STYLE = {
  common: { color: C.dim, stars: 1 },
  uncommon: { color: C.greenLight, stars: 2 },
  rare: { color: C.amber, stars: 3 },
  epic: { color: C.red, stars: 4 },
};
const POINTS_MILESTONES = [[500, 'common'], [1000, 'common'], [2000, 'uncommon'], [5000, 'rare'], [10000, 'epic']];
const MATCHES_MILESTONES = [[50, 'common'], [100, 'common'], [200, 'uncommon'], [500, 'rare'], [1000, 'epic']];
const STREAK_MILESTONES = [[3, 'common'], [5, 'uncommon'], [10, 'rare'], [20, 'epic']];
const TOTAL_POSSIBLE_BADGES = POINTS_MILESTONES.length + MATCHES_MILESTONES.length + STREAK_MILESTONES.length + 3; // + first-win, perfect-serve, perfect-return

function computeStreaks(matchLog, playerName) {
  const myMatches = matchLog
    .filter(m => m.nameA === playerName || m.nameB === playerName)
    .slice()
    .sort((a, b) => a.timestamp - b.timestamp);
  let best = 0, current = 0, losing = 0;
  myMatches.forEach(m => {
    if (m.winner === playerName) { current++; best = Math.max(best, current); losing = 0; }
    else { current = 0; losing++; }
  });
  return { current, best, losing };
}

function computePerfectMatchFlags(matchLog, playerName) {
  let perfectServe = false, perfectReturn = false;
  matchLog.forEach(m => {
    if (!m.pointLog || !m.pointLog.length) return;
    const isA = m.nameA === playerName, isB = m.nameB === playerName;
    if (!isA && !isB) return;
    const s = computeServeStats(m.pointLog);
    const mine = isA ? s.a : s.b;
    if (mine.servePts >= 6 && mine.serveWon === mine.servePts) perfectServe = true;
    if (mine.returnPts >= 6 && mine.returnWon === mine.returnPts) perfectReturn = true;
  });
  return { perfectServe, perfectReturn };
}

function trimTiers(list) {
  const idx = list.findIndex(b => !b.earned);
  return idx === -1 ? list : list.slice(0, idx + 1);
}

function computeBadges(matchLog, playerName, t) {
  const stats = aggregateStats(matchLog);
  const me = stats.find(s => s.name === playerName);
  const played = me ? me.played : 0;
  const points = me ? me.pointsFor : 0;
  const wins = me ? me.w : 0;
  const streak = computeStreaks(matchLog, playerName).best;
  const { perfectServe, perfectReturn } = computePerfectMatchFlags(matchLog, playerName);

  const pointsBadges = trimTiers(POINTS_MILESTONES.map(([n, tier]) => ({
    id: `points-${n}`, tier, icon: Zap, label: t('badge_points', { n }), earned: points >= n, current: points, goal: n,
  })));
  const matchesBadges = trimTiers(MATCHES_MILESTONES.map(([n, tier]) => ({
    id: `matches-${n}`, tier, icon: SwordsIcon, label: t('badge_matches', { n }), earned: played >= n, current: played, goal: n,
  })));
  const streakBadges = trimTiers(STREAK_MILESTONES.map(([n, tier]) => ({
    id: `streak-${n}`, tier, icon: Flame, label: t('badge_streak', { n }), earned: streak >= n, current: streak, goal: n,
  })));

  return [
    { id: 'first-win', tier: 'common', icon: Medal, label: t('badge_first_win'), earned: wins >= 1, current: wins, goal: 1 },
    ...pointsBadges,
    ...matchesBadges,
    ...streakBadges,
    { id: 'perfect-serve', tier: 'rare', icon: Target, label: t('badge_perfect_serve'), desc: t('badge_perfect_serve_desc'), earned: perfectServe, current: perfectServe ? 1 : 0, goal: 1 },
    { id: 'perfect-return', tier: 'rare', icon: Shield, label: t('badge_perfect_return'), desc: t('badge_perfect_return_desc'), earned: perfectReturn, current: perfectReturn ? 1 : 0, goal: 1 },
  ];
}

