function hashString(str) {
  let hash = 0;
  for (let i = 0; i < str.length; i++) hash = (hash * 31 + str.charCodeAt(i)) | 0;
  return Math.abs(hash);
}

function getPlayerTitle(earnedBadgeCount, totalPossible, playerName, lang, losingStreak = 0) {
  const losingPools = LOSING_STREAK_TITLES[lang] || LOSING_STREAK_TITLES.en;
  if (losingStreak >= 5) {
    const pool = losingPools[1];
    return pool[hashString(playerName || '') % pool.length];
  }
  if (losingStreak >= 3) {
    const pool = losingPools[0];
    return pool[hashString(playerName || '') % pool.length];
  }
  if (earnedBadgeCount <= 0) return null;
  const pct = totalPossible > 0 ? earnedBadgeCount / totalPossible : 0;
  const tierIdx = pct >= 0.9 ? 5 : pct >= 0.75 ? 4 : pct >= 0.6 ? 3 : pct >= 0.4 ? 2 : pct >= 0.2 ? 1 : 0;
  const pools = PLAYER_TITLES[lang] || PLAYER_TITLES.en;
  const pool = pools[tierIdx];
  return pool[hashString(playerName || '') % pool.length];
}

let sharedAudioCtx = null;
function playPointSound() {
  try {
    const AudioContextClass = window.AudioContext || window.webkitAudioContext;
    if (!AudioContextClass) return;
    if (!sharedAudioCtx) sharedAudioCtx = new AudioContextClass();
    const ctx = sharedAudioCtx;
    if (ctx.state === 'suspended') ctx.resume();
    const now = ctx.currentTime;
    const osc = ctx.createOscillator();
    const gain = ctx.createGain();
    osc.type = 'sine';
    osc.frequency.setValueAtTime(1100, now);
    osc.frequency.exponentialRampToValueAtTime(350, now + 0.07);
    gain.gain.setValueAtTime(0.0001, now);
    gain.gain.exponentialRampToValueAtTime(0.35, now + 0.005);
    gain.gain.exponentialRampToValueAtTime(0.0001, now + 0.09);
    osc.connect(gain);
    gain.connect(ctx.destination);
    osc.start(now);
    osc.stop(now + 0.1);
  } catch (e) { /* audio unavailable */ }
}

function formatClock(totalSec) {
  const m = Math.floor(totalSec / 60);
  const s = totalSec % 60;
  return `${m}:${s.toString().padStart(2, '0')}`;
}

function formatDuration(ms, lang) {
  const mins = Math.max(1, Math.round(ms / 60000));
  return tFn(lang, 'duration_fmt', { mins });
}

function pickFrom(arr) {
  return arr[Math.floor(Math.random() * arr.length)];
}

function fillTemplate(str, vars) {
  let out = str;
  Object.keys(vars).forEach(k => { out = out.split(`{${k}}`).join(vars[k]); });
  return out;
}

/* Report data is prepared once (stable random choices stored as indices) and
   rendered on demand in whatever language is currently active, so old match
   reports keep updating if you switch languages later. */
function prepareReportData({ setsA, setsB, sets, bestOf, durationMs }) {
  const lSets = Math.min(setsA, setsB);
  const wentDistance = sets.length === bestOf;
  const closest = sets.reduce((min, s) => Math.abs(s.a - s.b) < Math.abs(min.a - min.b) ? s : min, sets[0]);
  const closestMargin = Math.abs(closest.a - closest.b);
  let extraKind = 'none', closeScore = null;
  if (wentDistance) extraKind = 'distance';
  else if (lSets === 0) extraKind = 'blowout';
  else if (closestMargin <= 2) { extraKind = 'close'; closeScore = `${closest.a}-${closest.b}`; }
  return {
    sets, setsA, setsB, bestOf, durationMs,
    openerIndex: Math.floor(Math.random() * 1000),
    extraIndex: Math.floor(Math.random() * 1000),
    extraKind, closeScore,
  };
}

function periodLabel(cadence, n, t) {
  return cadence === 'monthly' ? t('period_month', { n }) : t('period_week', { n });
}

function renderContext(m, t) {
  if (m.kind === 'competition') return t('context_competition_period', { period: periodLabel(m.cadence, m.periodNumber, t) });
  if (m.kind === 'tournament') return t('context_tournament', { round: roundLabel(m.roundKey, t).toLowerCase() });
  return t(m.mode === 'dubbel' ? 'context_freeplay_doubles' : 'context_freeplay_singles');
}

function renderModeLabel(m, t) {
  if (m.kind === 'competition') return t('label_competition_period', { period: periodLabel(m.cadence, m.periodNumber, t) });
  if (m.kind === 'tournament') return t('label_tournament', { round: roundLabel(m.roundKey, t) });
  return t('label_freeplay');
}

function renderReport(m, lang, t) {
  const dict = TRANSLATIONS[lang] || TRANSLATIONS.en;
  const openers = dict.report_openers || TRANSLATIONS.en.report_openers;
  const opener = openers[m.openerIndex % openers.length];
  const winner = m.winner;
  const loser = winner === m.nameA ? m.nameB : m.nameA;
  const wSets = Math.max(m.setsA, m.setsB);
  const lSets = Math.min(m.setsA, m.setsB);
  const setsDetail = (m.sets || []).map(s => `${s.a}-${s.b}`).join(', ');

  let extra = '';
  if (m.extraKind === 'distance') {
    const list = dict.extra_distance_list || TRANSLATIONS.en.extra_distance_list;
    extra = fillTemplate(list[m.extraIndex % list.length], { winner, loser });
  } else if (m.extraKind === 'blowout') {
    const list = dict.extra_blowout_list || TRANSLATIONS.en.extra_blowout_list;
    extra = fillTemplate(list[m.extraIndex % list.length], { winner, loser });
  } else if (m.extraKind === 'close') {
    const list = dict.extra_close_list || TRANSLATIONS.en.extra_close_list;
    extra = fillTemplate(list[m.extraIndex % list.length], { score: m.closeScore });
  }

  const duration = formatDuration(m.durationMs, lang);
  const context = renderContext(m, t);
  return t('report_template', { opener, winner, loser, score: `${wSets}-${lSets}`, setsDetail, context, extra, duration });
}

/* Legacy-safe getters: matches recorded before this feature existed still have
   a frozen `report`/`modeLabel` string \u2014 those are shown as-is (they simply
   won't retranslate), while new matches render live in the current language. */
function getReportText(m, lang, t) {
  if (m.report) return m.report;
  return renderReport(m, lang, t);
}
function getModeLabel(m, t) {
  if (m.modeLabel) return m.modeLabel;
  return renderModeLabel(m, t);
}

/* ---- sharing: caption text + canvas result cards ---- */
function buildShareText({ nameA, nameB, setsA, setsB, winner, subtitle, t }) {
  const loser = winner === nameA ? nameB : nameA;
  const wSets = Math.max(setsA, setsB);
  const lSets = Math.min(setsA, setsB);
  return t('share_result_text', { winner, loser, score: `${wSets}-${lSets}`, sub: subtitle || '' });
}

function buildChampionShareText({ champion, subtitle, t }) {
  return t('share_champion_text', { champion, sub: subtitle || '' });
}

function drawResultCard({ nameA, nameB, setsA, setsB, winner, subtitle, headerText }) {
  const canvas = document.createElement('canvas');
  canvas.width = 1080; canvas.height = 1080;
  const ctx = canvas.getContext('2d');

  const bg = ctx.createRadialGradient(540, 260, 60, 540, 540, 820);
  bg.addColorStop(0, '#223244'); bg.addColorStop(1, '#060A0D');
  ctx.fillStyle = bg; ctx.fillRect(0, 0, 1080, 1080);

  ctx.fillStyle = 'rgba(255,255,255,0.05)';
  ctx.fillRect(0, 0, 1080, 70);

  ctx.textAlign = 'center';
  ctx.fillStyle = C.amber;
  ctx.font = '700 30px Inter, sans-serif';
  ctx.fillText(headerText, 540, 170);

  ctx.font = '800 58px Inter, sans-serif';
  ctx.fillStyle = winner === nameA ? C.amber : '#F3F7F6';
  ctx.fillText(nameA, 540, 400);

  ctx.font = '800 150px Inter, sans-serif';
  ctx.fillStyle = '#ffffff';
  ctx.fillText(`${setsA} \u2013 ${setsB}`, 540, 580);

  ctx.font = '800 58px Inter, sans-serif';
  ctx.fillStyle = winner === nameB ? C.amber : '#F3F7F6';
  ctx.fillText(nameB, 540, 700);

  ctx.font = '400 30px Inter, sans-serif';
  ctx.fillStyle = C.dim;
  ctx.fillText(subtitle || '', 540, 770);

  ctx.fillStyle = '#C81E70';
  ctx.fillRect(190, 900, 700, 34);
  ctx.fillStyle = '#F0378E';
  ctx.fillRect(190, 878, 700, 22);

  return canvas;
}

function drawChampionCard({ champion, subtitle, headerText, champLabel }) {
  const canvas = document.createElement('canvas');
  canvas.width = 1080; canvas.height = 1080;
  const ctx = canvas.getContext('2d');

  const bg = ctx.createRadialGradient(540, 300, 60, 540, 540, 820);
  bg.addColorStop(0, '#12563d'); bg.addColorStop(1, '#060A0D');
  ctx.fillStyle = bg; ctx.fillRect(0, 0, 1080, 1080);

  ctx.textAlign = 'center';
  ctx.fillStyle = C.amber;
  ctx.font = '700 28px Inter, sans-serif';
  ctx.fillText(headerText, 540, 170);

  ctx.font = '700 60px Inter, sans-serif';
  ctx.fillStyle = '#ffffff';
  ctx.fillText(champLabel, 540, 460);

  ctx.font = '800 78px Inter, sans-serif';
  ctx.fillStyle = C.amber;
  ctx.fillText(champion, 540, 590);

  ctx.font = '400 30px Inter, sans-serif';
  ctx.fillStyle = '#c9d6da';
  ctx.fillText(subtitle || '', 540, 660);

  return canvas;
}

