/* Share sheet: native share (covers Instagram/WhatsApp/Facebook on mobile) + web fallbacks */
function ShareModal({ shareText, drawCard, onClose }) {
  const { t } = useT();
  const [imgUrl, setImgUrl] = useState(null);
  const [busy, setBusy] = useState(false);
  const [copied, setCopied] = useState(false);

  useEffect(() => {
    try {
      const canvas = drawCard();
      setImgUrl(canvas.toDataURL('image/png'));
    } catch (e) { /* canvas generation failed, buttons below still work */ }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const canNativeShare = typeof navigator !== 'undefined' && !!navigator.share;

  async function nativeShare() {
    setBusy(true);
    try {
      const canvas = drawCard();
      canvas.toBlob(async (blob) => {
        try {
          const file = blob ? new File([blob], 'tafeltennis-resultaat.png', { type: 'image/png' }) : null;
          if (file && navigator.canShare && navigator.canShare({ files: [file] })) {
            await navigator.share({ files: [file], text: shareText, title: t('card_header') });
          } else {
            await navigator.share({ text: shareText, title: t('card_header') });
          }
        } catch (e) { /* user cancelled or share failed, no action needed */ }
        setBusy(false);
      }, 'image/png');
    } catch (e) { setBusy(false); }
  }

  function shareWhatsApp() {
    window.open(`https://wa.me/?text=${encodeURIComponent(shareText)}`, '_blank');
  }
  function shareFacebook() {
    const url = (typeof window !== 'undefined' && window.location && window.location.href) ? window.location.href : 'https://claude.ai';
    window.open(`https://www.facebook.com/sharer/sharer.php?u=${encodeURIComponent(url)}&quote=${encodeURIComponent(shareText)}`, '_blank');
  }
  function downloadImage() {
    if (!imgUrl) return;
    const a = document.createElement('a');
    a.href = imgUrl; a.download = 'tafeltennis-resultaat.png'; a.click();
  }
  async function copyText() {
    try { await navigator.clipboard.writeText(shareText); setCopied(true); setTimeout(() => setCopied(false), 1800); } catch (e) { /* clipboard unavailable */ }
  }

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-3" style={{ background: 'rgba(5,10,13,0.85)' }}>
      <div className="w-full max-w-sm rounded-2xl p-5" style={{ background: C.bg, border: `1px solid ${C.line}` }}>
        <div className="flex justify-between items-center mb-3">
          <span className="tt-display text-xl" style={{ color: C.text }}>{t('share_title')}</span>
          <button onClick={onClose} className="p-1 rounded-lg" style={{ background: C.panel2 }}><X size={16} color={C.text} /></button>
        </div>

        {imgUrl && <img src={imgUrl} alt="" className="rounded-xl mb-4 w-full" style={{ border: `1px solid ${C.line}` }} />}

        <div className="flex flex-col gap-2">
          {canNativeShare && (
            <PrimaryButton onClick={nativeShare} disabled={busy} style={{ width: '100%' }}>
              <span className="flex items-center justify-center gap-2"><Share2 size={16} /> {busy ? t('share_busy') : t('share_native')}</span>
            </PrimaryButton>
          )}
          <div className="grid grid-cols-2 gap-2">
            <GhostButton onClick={shareWhatsApp} style={{ textAlign: 'center' }}>{t('share_whatsapp')}</GhostButton>
            <GhostButton onClick={shareFacebook} style={{ textAlign: 'center' }}>{t('share_facebook')}</GhostButton>
          </div>
          <GhostButton onClick={downloadImage} style={{ width: '100%', textAlign: 'center' }}>{t('share_download')}</GhostButton>
          <GhostButton onClick={copyText} style={{ width: '100%', textAlign: 'center' }}>{copied ? t('share_copied') : t('share_copy')}</GhostButton>
        </div>

        <div className="tt-body text-xs mt-3 text-center" style={{ color: C.dim }}>
          {t('share_ig_note')}
        </div>
      </div>
    </div>
  );
}

/* Match detail: per-set score progression chart + serve/return stats */
function MatchDetailModal({ match, onClose }) {
  const { t } = useT();
  const hasData = match.pointLog && match.pointLog.length > 0;
  const serveStats = hasData ? computeServeStats(match.pointLog) : null;

  const setsCount = match.setsA + match.setsB;
  const chartsBySet = [];
  if (hasData) {
    for (let i = 0; i < setsCount; i++) {
      const pts = match.pointLog.filter(p => p[4] === i);
      const data = [{ idx: 0, [match.nameA]: 0, [match.nameB]: 0 }];
      pts.forEach((p, idx) => {
        data.push({ idx: idx + 1, [match.nameA]: p[2], [match.nameB]: p[3] });
      });
      chartsBySet.push(data);
    }
  }

  function pct(won, total) { return total > 0 ? Math.round((won / total) * 100) : 0; }

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-3" style={{ background: 'rgba(5,10,13,0.85)' }}>
      <div className="w-full max-w-md rounded-2xl p-5" style={{ background: C.bg, border: `1px solid ${C.line}`, maxHeight: '90vh', overflowY: 'auto' }}>
        <div className="flex justify-between items-center mb-3">
          <span className="tt-display text-xl" style={{ color: C.text }}>{t('match_detail_title')}</span>
          <button onClick={onClose} className="p-1 rounded-lg" style={{ background: C.panel2 }}><X size={16} color={C.text} /></button>
        </div>

        <div className="flex items-center justify-center gap-3 mb-1">
          <span className="tt-display text-lg truncate" style={{ color: match.winner === match.nameA ? C.amber : C.text }}>{match.nameA}</span>
          <span className="tt-display text-2xl px-2.5 py-0.5 rounded-lg" style={{ background: C.panel2, color: C.text, border: `1px solid ${C.line}` }}>{match.setsA}&ndash;{match.setsB}</span>
          <span className="tt-display text-lg truncate" style={{ color: match.winner === match.nameB ? C.amber : C.text }}>{match.nameB}</span>
        </div>
        <div className="tt-body text-xs text-center mb-4" style={{ color: C.dim }}>
          {getModeLabel(match, t)} &bull; {new Date(match.timestamp).toLocaleString()}
        </div>

        {!hasData ? (
          <div className="tt-body text-sm text-center" style={{ color: C.dim }}>{t('match_detail_no_data')}</div>
        ) : (
          <>
            {chartsBySet.map((data, i) => (
              <div key={i} className="mb-4">
                <div className="tt-body text-xs font-semibold mb-1" style={{ color: C.dim }}>{t('set_label', { n: i + 1 })}</div>
                <div style={{ width: '100%', height: 130 }}>
                  <ResponsiveContainer>
                    <LineChart data={data} margin={{ top: 5, right: 8, left: -20, bottom: 0 }}>
                      <CartesianGrid strokeDasharray="3 3" stroke={C.line} />
                      <XAxis dataKey="idx" tick={{ fill: C.dim, fontSize: 10 }} />
                      <YAxis tick={{ fill: C.dim, fontSize: 10 }} allowDecimals={false} />
                      <Tooltip contentStyle={{ background: C.panel2, border: `1px solid ${C.line}`, borderRadius: 8, color: C.text }} />
                      <Line type="monotone" dataKey={match.nameA} stroke={C.amber} strokeWidth={2} dot={false} />
                      <Line type="monotone" dataKey={match.nameB} stroke={C.greenLight} strokeWidth={2} dot={false} />
                    </LineChart>
                  </ResponsiveContainer>
                </div>
              </div>
            ))}

            <div className="tt-body text-sm font-semibold mb-2 mt-2" style={{ color: C.dim }}>{t('serve_stats_title')}</div>
            <div className="flex flex-col gap-2">
              {[{ name: match.nameA, s: serveStats.a }, { name: match.nameB, s: serveStats.b }].map(row => (
                <div key={row.name} className="rounded-xl p-3" style={{ background: C.panel, border: `1px solid ${C.line}` }}>
                  <div className="tt-body text-sm font-semibold mb-1.5" style={{ color: C.text }}>{row.name}</div>
                  <div className="flex justify-between tt-body text-xs" style={{ color: C.dim }}>
                    <span>{t('own_serve_label')}: {row.s.serveWon}/{row.s.servePts} ({pct(row.s.serveWon, row.s.servePts)}%)</span>
                    <span>{t('return_label')}: {row.s.returnWon}/{row.s.returnPts} ({pct(row.s.returnWon, row.s.returnPts)}%)</span>
                  </div>
                </div>
              ))}
            </div>
          </>
        )}
      </div>
    </div>
  );
}

/* hook: lazily fetch photos for a list of names */
function usePhotos(names, photos, setPhotos) {
  const key = names.join('|');
  useEffect(() => {
    let cancelled = false;
    (async () => {
      for (const name of names) {
        if (photos[name] !== undefined) continue;
        try {
          const r = await window.storage.get(photoKey(name), false);
          if (!cancelled) setPhotos(p => ({ ...p, [name]: r && r.value ? r.value : null }));
        } catch (e) {
          if (!cancelled) setPhotos(p => ({ ...p, [name]: null }));
        }
      }
    })();
    return () => { cancelled = true; };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [key]);
}

/* ============================= SCOREBOARD ENGINE ============================= */
function MatchScoreboard({ nameA, nameB, bestOf, settings = {}, mode = 'enkel', pairA = null, pairB = null, onComplete, onCancel }) {
  const { t, lang } = useT();
  const { coinToss = false, voice = false, setBreaks: breaksEnabled = true, pointSound = true } = settings;
  const isDoubles = mode === 'dubbel' && pairA && pairB && pairA.length === 2 && pairB.length === 2;
  const [phase, setPhase] = useState('setup');
  const [flipping, setFlipping] = useState(false);
  const [tossWinnerSide, setTossWinnerSide] = useState(null);
  const [sideChoice, setSideChoice] = useState(false);

  useEffect(() => {
    function goFullscreen() {
      try {
        const el = document.documentElement;
        if (!document.fullscreenElement && !document.webkitFullscreenElement) {
          if (el.requestFullscreen) el.requestFullscreen().catch(() => {});
          else if (el.webkitRequestFullscreen) el.webkitRequestFullscreen();
        }
      } catch (e) { /* fullscreen unavailable on this device/browser */ }
    }
    function exitFullscreenIfActive() {
      try {
        if (document.fullscreenElement || document.webkitFullscreenElement) {
          if (document.exitFullscreen) document.exitFullscreen();
          else if (document.webkitExitFullscreen) document.webkitExitFullscreen();
        }
      } catch (e) { /* ignore */ }
    }
    const mq = window.matchMedia('(orientation: landscape)');
    function handleOrientationChange(e) {
      if (e.matches) goFullscreen();
      else exitFullscreenIfActive();
    }
    if (mq.matches) goFullscreen();
    mq.addEventListener('change', handleOrientationChange);
    return () => mq.removeEventListener('change', handleOrientationChange);
  }, []);

  useEffect(() => () => {
    try {
      if (document.fullscreenElement || document.webkitFullscreenElement) {
        if (document.exitFullscreen) document.exitFullscreen();
        else if (document.webkitExitFullscreen) document.webkitExitFullscreen();
      }
    } catch (e) { /* ignore */ }
  }, []);

  const [match, setMatch] = useState({
    sets: [], curA: 0, curB: 0, initialServer: 0, serverOverride: null,
    endsFlipped: false, deciderSwapDone: false, pointLog: [],
    doublesIdx: 0, doublesBlock: 0,
  });
  const [history, setHistory] = useState([]);
  const [startTime, setStartTime] = useState(null);
  const [elapsedSec, setElapsedSec] = useState(0);
  const [breakSeconds, setBreakSeconds] = useState(60);
  const prevSetsLengthRef = useRef(0);

  const need = majority(bestOf);
  const setsA = match.sets.filter(s => s.a > s.b).length;
  const setsB = match.sets.filter(s => s.b > s.a).length;
  const matchOver = setsA === need || setsB === need;
  const isDeciderSet = setsA === need - 1 && setsB === need - 1;
  const matchOverRef = useRef(matchOver);
  useEffect(() => { matchOverRef.current = matchOver; }, [matchOver]);

  useEffect(() => {
    if (startTime === null) return;
    const iv = setInterval(() => setElapsedSec(Math.floor((Date.now() - startTime) / 1000)), 1000);
    return () => clearInterval(iv);
  }, [startTime]);

  useEffect(() => {
    if (match.sets.length > prevSetsLengthRef.current) {
      prevSetsLengthRef.current = match.sets.length;
      if (!matchOver && phase === 'playing' && breaksEnabled) {
        setBreakSeconds(60);
        setPhase('break');
      }
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [match.sets.length, matchOver]);

  useEffect(() => {
    if (phase !== 'break') return;
    if (breakSeconds <= 0) { setPhase('playing'); return; }
    const timer = setTimeout(() => setBreakSeconds(s => s - 1), 1000);
    return () => clearTimeout(timer);
  }, [phase, breakSeconds]);

  function addPoint(side) {
    if (matchOverRef.current) return;
    if (pointSound) playPointSound();
    const serverAtPoint = srv;
    setHistory(h => [...h, match]);
    setMatch(prev => {
      const { sets, curA, curB, initialServer, endsFlipped, deciderSwapDone, pointLog, doublesIdx, doublesBlock } = prev;
      let a = curA, b = curB;
      if (side === 'a') a++; else b++;

      const setsAcount = sets.filter(s => s.a > s.b).length;
      const setsBcount = sets.filter(s => s.b > s.a).length;
      const isDecider = setsAcount === need - 1 && setsBcount === need - 1;

      let newEndsFlipped = endsFlipped;
      let newDeciderSwapDone = deciderSwapDone;
      if (isDecider && !deciderSwapDone && (a === 5 || b === 5)) {
        newEndsFlipped = !newEndsFlipped;
        newDeciderSwapDone = true;
      }

      const blockSize = (a >= 10 && b >= 10) ? 1 : 2;
      let newDoublesIdx = doublesIdx;
      let newDoublesBlock = doublesBlock + 1;
      if (newDoublesBlock >= blockSize) {
        newDoublesIdx = (newDoublesIdx + 1) % 4;
        newDoublesBlock = 0;
      }

      const newPointLog = [...pointLog, [side === 'a' ? 0 : 1, serverAtPoint, a, b, sets.length]];

      if (isSetWon(a, b)) {
        return {
          sets: [...sets, { a, b }],
          curA: 0, curB: 0,
          initialServer: 1 - initialServer,
          serverOverride: null,
          endsFlipped: !newEndsFlipped,
          deciderSwapDone: false,
          pointLog: newPointLog,
          doublesIdx: newDoublesIdx,
          doublesBlock: newDoublesBlock,
        };
      }
      return {
        ...prev, curA: a, curB: b, endsFlipped: newEndsFlipped, deciderSwapDone: newDeciderSwapDone,
        pointLog: newPointLog, doublesIdx: newDoublesIdx, doublesBlock: newDoublesBlock,
      };
    });
  }

  function undo() {
    setHistory(h => {
      if (h.length === 0) return h;
      setMatch(h[h.length - 1]);
      return h.slice(0, -1);
    });
  }

  function server() {
    if (isDoubles) {
      if (match.serverOverride !== null) return match.serverOverride % 2;
      return match.doublesIdx % 2;
    }
    if (match.serverOverride !== null) return match.serverOverride;
    const total = match.curA + match.curB;
    if (match.curA >= 10 && match.curB >= 10) return total % 2 === 0 ? match.initialServer : 1 - match.initialServer;
    return Math.floor(total / 2) % 2 === 0 ? match.initialServer : 1 - match.initialServer;
  }
  const srv = server();

  /* which individual is serving right now, for doubles display: cycle order is [A1, B1, A2, B2] */
  function currentServerName() {
    if (!isDoubles) return null;
    const idx = match.serverOverride !== null ? match.serverOverride : match.doublesIdx;
    const cycle = [pairA[0], pairB[0], pairA[1], pairB[1]];
    return cycle[idx % 4];
  }

  function confirmResult() {
    onComplete({ winner: setsA > setsB ? 'a' : 'b', score: { setsA, setsB, sets: match.sets, pointLog: match.pointLog }, durationMs: startTime !== null ? Date.now() - startTime : 0 });
  }

  function doToss() {
    setFlipping(true);
    setTimeout(() => {
      const winnerSide = Math.random() < 0.5 ? 0 : 1;
      setTossWinnerSide(winnerSide);
      setMatch(m => ({ ...m, initialServer: winnerSide }));
      setFlipping(false);
    }, 900);
  }

  /* ---- voice recognition ---- */
  const recognitionRef = useRef(null);
  const [listening, setListening] = useState(false);
  const listeningRef = useRef(false);
  useEffect(() => { listeningRef.current = listening; }, [listening]);
  const voiceSupported = typeof window !== 'undefined' && !!(window.SpeechRecognition || window.webkitSpeechRecognition);
  const [voiceMsg, setVoiceMsg] = useState('');

  function toggleListening() {
    if (!voiceSupported) return;
    if (listening) {
      recognitionRef.current && recognitionRef.current.stop();
      setListening(false);
      return;
    }
    const SR = window.SpeechRecognition || window.webkitSpeechRecognition;
    const rec = new SR();
    rec.lang = 'en-US';
    rec.continuous = true;
    rec.interimResults = false;
    rec.onresult = (e) => {
      const transcript = e.results[e.results.length - 1][0].transcript.toLowerCase();
      setVoiceMsg(transcript);
      const an = nameA.toLowerCase(), bn = nameB.toLowerCase();
      if (transcript.includes(an) || transcript.includes('left') || transcript.includes('links')) addPoint('a');
      else if (transcript.includes(bn) || transcript.includes('right') || transcript.includes('rechts')) addPoint('b');
    };
    rec.onerror = () => setListening(false);
    rec.onend = () => {
      if (listeningRef.current) { try { rec.start(); } catch (e) {} }
    };
    recognitionRef.current = rec;
    try { rec.start(); setListening(true); } catch (e) { setListening(false); }
  }

  useEffect(() => () => {
    recognitionRef.current && recognitionRef.current.stop();
  }, []);

  /* ---- render: setup phase (optional coin toss + side choice, clock starts on "Start match") ---- */
  if (phase === 'setup') {
    const readyToStart = !coinToss || tossWinnerSide !== null;
    const previewLeft = sideChoice ? nameB : nameA;
    const previewRight = sideChoice ? nameA : nameB;

    function handleStartMatch() {
      setMatch(m => ({ ...m, endsFlipped: sideChoice }));
      setStartTime(Date.now());
      setPhase('playing');
      try {
        const el = document.documentElement;
        if (!document.fullscreenElement && !document.webkitFullscreenElement) {
          if (el.requestFullscreen) el.requestFullscreen().catch(() => {});
          else if (el.webkitRequestFullscreen) el.webkitRequestFullscreen();
        }
      } catch (e) { /* fullscreen unavailable on this device/browser */ }
    }

    return (
      <div className="fixed inset-0 z-50 flex items-center justify-center p-3" style={{ background: 'rgba(5,10,13,0.85)' }}>
        <div className="w-full max-w-sm rounded-2xl p-6 text-center" style={{ background: C.bg, border: `1px solid ${C.line}` }}>
          {coinToss && (
            <>
              <div className="tt-body text-xs uppercase tracking-wide mb-4" style={{ color: C.dim }}>{t('toss_title')}</div>
              <div
                className={`mx-auto mb-5 flex items-center justify-center tt-display text-2xl ${flipping ? 'animate-spin' : ''}`}
                style={{ width: 96, height: 96, borderRadius: '9999px', background: `linear-gradient(135deg, ${C.amber}, ${C.red})`, color: '#1a0a04' }}
              >
                TT
              </div>
              {tossWinnerSide === null ? (
                <PrimaryButton onClick={doToss} disabled={flipping} style={{ marginBottom: 8 }}>{flipping ? t('toss_flipping') : t('toss_btn')}</PrimaryButton>
              ) : (
                <div className="tt-display text-2xl mb-4" style={{ color: C.text }}>
                  {t('toss_winner', { name: tossWinnerSide === 0 ? nameA : nameB })}
                </div>
              )}
            </>
          )}

          {readyToStart && (
            <>
              <div className="tt-display text-xl mb-3" style={{ color: C.text }}>
                {previewLeft} <span style={{ color: C.dim }}>vs</span> {previewRight}
              </div>
              <GhostButton onClick={() => setSideChoice(s => !s)} style={{ marginBottom: 16 }}>
                <span className="flex items-center gap-2"><RotateCw size={14} /> {t('swap_sides_btn')}</span>
              </GhostButton>
              <div>
                <PrimaryButton onClick={handleStartMatch}>{t('btn_start_match')}</PrimaryButton>
              </div>
            </>
          )}

          <div className="mt-4">
            <button onClick={onCancel} className="tt-body text-xs" style={{ color: C.dim }}>{t('btn_cancel')}</button>
          </div>
        </div>
      </div>
    );
  }

  /* ---- render: break phase (1 min between sets) ---- */
  if (phase === 'break') {
    return (
      <div className="fixed inset-0 z-50 flex items-center justify-center p-3" style={{ background: 'rgba(5,10,13,0.85)' }}>
        <div className="w-full max-w-sm rounded-2xl p-6 text-center" style={{ background: C.bg, border: `1px solid ${C.line}` }}>
          <div className="tt-body text-xs uppercase tracking-wide mb-4" style={{ color: C.dim }}>{t('match_break_title')}</div>
          <div className="tt-display text-6xl mb-4" style={{ color: C.amber }}>{formatClock(breakSeconds)}</div>
          <div className="tt-body text-sm mb-5" style={{ color: C.text }}>{t('sides_swapped')}</div>
          <PrimaryButton onClick={() => setPhase('playing')}>{t('match_break_continue')}</PrimaryButton>
        </div>
      </div>
    );
  }

  /* ---- render: playing / finished ---- */
  const cols = [
    { side: 'a', name: nameA, val: match.curA },
    { side: 'b', name: nameB, val: match.curB },
  ];
  const displayCols = match.endsFlipped ? [cols[1], cols[0]] : cols;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-3" style={{ background: 'rgba(5,10,13,0.85)' }}>
      <div
        className="w-full max-w-md landscape:max-w-2xl rounded-2xl p-5"
        style={{ background: C.bg, border: `1px solid ${C.line}`, maxHeight: '95vh', overflowY: 'auto' }}
      >
        <div className="flex justify-between items-center mb-2">
          <span className="tt-body text-xs flex items-center gap-1" style={{ color: C.dim }}>
            <Clock size={12} color={C.dim} /> {formatClock(elapsedSec)}
          </span>
        </div>
        <div className="flex justify-between items-center mb-4">
          <span className="tt-body text-xs uppercase tracking-wide" style={{ color: C.dim }}>{t('sb_bestof', { bestOf, need })}</span>
          <button onClick={onCancel} className="p-1 rounded-lg" style={{ background: C.panel2 }}><X size={16} color={C.text} /></button>
        </div>

        <div className="flex gap-1.5 mb-4 flex-wrap justify-center">
          {match.sets.map((s, i) => (
            <div key={i} className="tt-body text-xs px-2 py-1 rounded-md" style={{ background: C.panel2, color: C.dim }}>
              {s.a}-{s.b}
            </div>
          ))}
        </div>

        {!matchOver ? (
          <>
            <div
              className="relative rounded-2xl mb-1 overflow-hidden"
              style={{ background: 'linear-gradient(180deg, #0F7A4E 0%, #0A5638 100%)', border: '3px solid rgba(255,255,255,0.55)', padding: '14px 10px 10px' }}
            >
              <div style={{ position: 'absolute', left: '50%', top: 10, bottom: 10, width: 0, borderLeft: '3px dashed rgba(255,255,255,0.6)', transform: 'translateX(-50%)', pointerEvents: 'none' }} />
              <div style={{ position: 'absolute', inset: 6, border: '2px solid rgba(255,255,255,0.25)', borderRadius: 14, pointerEvents: 'none' }} />

              <div className="grid grid-cols-2 gap-3 relative">
                {displayCols.map(col => {
                  const serving = srv === (col.side === 'a' ? 0 : 1);
                  const servingIndividual = serving && isDoubles ? currentServerName() : null;
                  return (
                    <button
                      key={col.side}
                      onClick={() => addPoint(col.side)}
                      className="text-center py-1 rounded-xl active:scale-[0.98] transition-transform w-full"
                      style={{ WebkitTapHighlightColor: 'transparent', background: 'transparent', border: 'none' }}
                    >
                      <div className="flex items-center justify-center gap-1.5 mb-1" style={{ minHeight: 30 }}>
                        {serving && <PaddleIcon color={col.side === 'a' ? C.red : C.paddleBlack} size={24} flip={col.side === 'b'} />}
                        <span className="tt-body text-sm font-semibold truncate" style={{ color: '#fff' }}>{col.name}</span>
                      </div>
                      {servingIndividual && (
                        <div className="tt-body text-xs mb-1" style={{ color: 'rgba(255,255,255,0.8)' }}>{t('serving_label', { name: servingIndividual })}</div>
                      )}
                      <div className="tt-display text-6xl landscape:text-8xl mb-3" style={{ color: '#fff' }}>{col.val}</div>
                      <div className="flex gap-2 justify-center pointer-events-none">
                        <div className="p-3 rounded-xl" style={{ background: 'rgba(255,255,255,0.18)', border: '1px solid rgba(255,255,255,0.35)' }}>
                          <Plus size={18} color="#fff" />
                        </div>
                      </div>
                      <div className="tt-body text-xs mt-2" style={{ color: 'rgba(255,255,255,0.75)' }}>{t('sets_prefix')}: {col.side === 'a' ? setsA : setsB}</div>
                    </button>
                  );
                })}
              </div>
            </div>
            {isDeciderSet && match.deciderSwapDone ? (
              <div className="tt-body text-xs text-center mb-2 py-2 rounded-lg font-semibold" style={{ color: '#fff', background: C.red }}>
                {t('sides_swapped')}
              </div>
            ) : match.sets.length > 0 && (
              <div className="tt-body text-xs text-center mb-2" style={{ color: C.amber }}>{t('sides_swapped')}</div>
            )}
            <button
              onClick={undo}
              disabled={history.length === 0}
              className="tt-body w-full py-3 rounded-xl flex items-center justify-center gap-2 font-semibold disabled:opacity-30 mt-2"
              style={{ background: C.panel2, color: C.text, border: `1px solid ${C.line}` }}
            >
              <RotateCcw size={17} /> {t('btn_undo')}
            </button>
            <div className="flex justify-center mt-2">
              <button
                onClick={() => setMatch(m => {
                  if (isDoubles) {
                    const cur = m.serverOverride !== null ? m.serverOverride : m.doublesIdx;
                    return { ...m, serverOverride: (cur + 1) % 4 };
                  }
                  return { ...m, serverOverride: 1 - srv };
                })}
                className="tt-body text-xs px-3 py-2 rounded-lg"
                style={{ background: 'transparent', color: C.dim }}
              >
                {t('swap_serve')}
              </button>
            </div>

            {voice && (
              <div className="mt-4 text-center pt-3" style={{ borderTop: `1px solid ${C.line}` }}>
                {voiceSupported ? (
                  <>
                    <button
                      onClick={toggleListening}
                      className="tt-body text-xs px-3 py-2 rounded-lg flex items-center gap-1.5 mx-auto"
                      style={{ background: listening ? C.red : C.panel2, color: listening ? '#fff' : C.dim }}
                    >
                      <Mic size={13} /> {listening ? t('voice_listening') : t('voice_start')}
                    </button>
                    <div className="tt-body text-xs mt-2" style={{ color: C.dim }}>
                      {t('voice_hint')}
                    </div>
                    {voiceMsg && <div className="tt-body text-xs mt-1" style={{ color: C.dim }}>{t('voice_heard', { t: voiceMsg })}</div>}
                  </>
                ) : (
                  <div className="tt-body text-xs" style={{ color: C.dim }}>{t('voice_unsupported')}</div>
                )}
              </div>
            )}
          </>
        ) : (
          <div className="text-center py-4">
            <Trophy size={32} color={C.amber} className="mx-auto mb-2" />
            <div className="tt-display text-3xl mb-1" style={{ color: C.text }}>
              {t('sb_win', { name: setsA > setsB ? nameA : nameB })}
            </div>
            <div className="tt-body text-sm mb-5" style={{ color: C.dim }}>{t('sb_final_score', { a: setsA, b: setsB })}</div>
            <PrimaryButton onClick={confirmResult}>{t('btn_confirm_result')}</PrimaryButton>
          </div>
        )}
      </div>
    </div>
  );
}

/* ============================= NEWS BULLETIN (collapsible, rally-ticker themed) ============================= */
function NewsBulletin({ matchLog }) {
  const { t, lang } = useT();
  const [expanded, setExpanded] = useState(false);
  const [detailMatch, setDetailMatch] = useState(null);
  const recent = matchLog.slice(0, 5);
  if (recent.length === 0) return null;
  const latest = recent[0];

  return (
    <div className="rounded-2xl overflow-hidden" style={{ background: C.panel, border: `1px solid ${C.line}` }}>
      <button onClick={() => setExpanded(e => !e)} className="w-full flex items-center justify-between gap-2 px-3 py-2.5">
        <div className="flex items-center gap-2.5 min-w-0">
          <div
            className="flex items-center gap-1.5 flex-shrink-0 px-2 py-0.5 rounded-full"
            style={{ background: C.paddleBlack, border: `1px solid ${C.red}` }}
          >
            <span className="ball-bounce-small" style={{ display: 'inline-block', width: 6, height: 6, borderRadius: '9999px', background: C.ball }} />
            <span className="tt-display text-[10px]" style={{ color: C.ball, letterSpacing: '0.08em' }}>{t('news_badge')}</span>
          </div>
        </div>
        <ChevronDown size={16} color={C.dim} style={{ transform: expanded ? 'rotate(180deg)' : 'none', transition: 'transform 0.15s', flexShrink: 0 }} />
      </button>

      {!expanded && (
        <button onClick={() => setExpanded(true)} className="w-full flex items-center justify-center gap-2 px-3 pb-3">
          <span className="tt-display text-base truncate" style={{ color: latest.winner === latest.nameA ? C.amber : C.text }}>{latest.nameA}</span>
          <span className="tt-display text-lg px-2 py-0.5 rounded-lg" style={{ background: C.panel2, color: C.text, border: `1px solid ${C.line}` }}>{latest.setsA}&ndash;{latest.setsB}</span>
          <span className="tt-display text-base truncate" style={{ color: latest.winner === latest.nameB ? C.amber : C.text }}>{latest.nameB}</span>
        </button>
      )}

      {expanded && (
        <div className="flex flex-col px-3 pb-3">
          {recent.map((m, idx) => (
            <button
              key={m.id}
              onClick={() => setDetailMatch(m)}
              className="pt-2.5 pb-2.5 w-full text-left"
              style={idx > 0 ? { borderTop: `1px dashed ${C.line}` } : undefined}
            >
              <div className="flex items-center justify-center gap-2 mb-1">
                <span className="tt-display text-base truncate" style={{ color: m.winner === m.nameA ? C.amber : C.text }}>{m.nameA}</span>
                <span className="tt-display text-lg px-2 py-0.5 rounded-lg flex-shrink-0" style={{ background: C.panel2, color: C.text, border: `1px solid ${C.line}` }}>{m.setsA}&ndash;{m.setsB}</span>
                <span className="tt-display text-base truncate" style={{ color: m.winner === m.nameB ? C.amber : C.text }}>{m.nameB}</span>
              </div>
              <div className="tt-body text-[11px] text-center mb-1" style={{ color: C.dim }}>
                {getModeLabel(m, t)} &bull; {new Date(m.timestamp).toLocaleString(undefined, { day: '2-digit', month: '2-digit', hour: '2-digit', minute: '2-digit' })}
              </div>
              <div className="tt-body text-xs text-center" style={{ color: C.text }}>{getReportText(m, lang, t)}</div>
            </button>
          ))}
        </div>
      )}
      {detailMatch && <MatchDetailModal match={detailMatch} onClose={() => setDetailMatch(null)} />}
    </div>
  );
}

/* ============================= SIDEBAR ============================= */
function Sidebar({ view, setView, hasCompetition }) {
  const { t } = useT();
  const items = [
    { key: 'home', label: t('nav_home'), icon: HomeIcon, match: v => v === 'home' },
    { key: 'myprofile', label: t('nav_profile'), icon: User, match: v => v === 'myprofile' },
    { key: 'freeplay-setup', label: t('nav_freeplay'), icon: Swords, match: v => v.startsWith('freeplay') },
    { key: hasCompetition ? 'competition-play' : 'competition-setup', label: t('nav_competition'), icon: Users, match: v => v.startsWith('competition') },
    { key: 'tournament-setup', label: t('nav_tournament'), icon: Trophy, match: v => v.startsWith('tournament') },
    { key: 'leaderboard', label: t('nav_stats'), icon: BarChart2, match: v => v === 'leaderboard' || v === 'player-detail' || v === 'h2h' },
    { key: 'friends', label: t('nav_friends'), icon: UserPlus, match: v => v === 'friends' },
    { key: 'groups', label: t('nav_groups'), icon: Building2, match: v => v === 'groups' || v === 'group-detail' },
    { key: 'settings', label: t('nav_settings'), icon: SettingsIcon, match: v => v === 'settings' },
  ];
  return (
    <div className="flex flex-col items-stretch flex-shrink-0" style={{ width: 68, background: C.panel, borderRight: `1px solid ${C.line}`, minHeight: '100vh' }}>
      {items.map(it => {
        const active = it.match(view);
        return (
          <button
            key={it.key}
            onClick={() => setView(it.key)}
            className="flex flex-col items-center gap-1 py-3"
            style={{ background: active ? 'rgba(11,110,79,0.35)' : 'transparent', borderLeft: active ? `3px solid ${C.amber}` : '3px solid transparent' }}
          >
            <it.icon size={19} color={active ? C.amber : C.dim} />
            <span className="tt-body" style={{ fontSize: 9, color: active ? C.text : C.dim, lineHeight: 1 }}>{it.label}</span>
          </button>
        );
      })}
    </div>
  );
}

/* ============================= LANGUAGE PICKER ============================= */
function LanguagePicker() {
  const { lang, setLang } = useT();
  const [open, setOpen] = useState(false);
  const current = LANGUAGES.find(l => l.code === lang) || LANGUAGES[0];
  return (
    <div style={{ position: 'absolute', top: 10, right: 10, zIndex: 10 }}>
      <button onClick={() => setOpen(o => !o)} className="flex items-center gap-1.5 px-2.5 py-1.5 rounded-full" style={{ background: 'rgba(0,0,0,0.35)', border: `1px solid ${C.line}` }}>
        <Globe size={15} color="#fff" />
        <span className="tt-body text-xs font-semibold" style={{ color: '#fff' }}>{current.short}</span>
      </button>
      {open && (
        <div className="absolute right-0 mt-2 rounded-xl overflow-hidden" style={{ background: C.panel, border: `1px solid ${C.line}`, minWidth: 170, maxHeight: 320, overflowY: 'auto' }}>
          {LANGUAGES.map(l => (
            <button
              key={l.code}
              onClick={() => { setLang(l.code); setOpen(false); }}
              className="w-full text-left px-3 py-2 flex items-center gap-2 tt-body text-sm"
              style={{ background: l.code === lang ? C.panel2 : 'transparent', color: C.text }}
            >
              <span>{l.flag}</span><span>{l.label}</span>
            </button>
          ))}
        </div>
      )}
    </div>
  );
}

/* ============================= HOME ============================= */
/* ============================= AUTH ============================= */
function AuthScreen() {
  const { t } = useT();
  const [loading, setLoading] = useState(null); // null | 'google' | 'facebook' | 'guest'
  const [error, setError] = useState('');

  useEffect(() => {
    // Supabase appends error details to the URL hash when an OAuth redirect fails
    // (e.g. mismatched credentials) — surface that instead of failing silently.
    const hash = window.location.hash ? window.location.hash.substring(1) : '';
    const params = new URLSearchParams(hash || window.location.search);
    const errDesc = params.get('error_description') || params.get('error');
    if (errDesc) {
      setError(decodeURIComponent(errDesc).replace(/\+/g, ' '));
      window.history.replaceState(null, '', window.location.pathname);
    }
  }, []);

  async function signInWithProvider(provider) {
    setLoading(provider);
    setError('');
    // Clear any leftover PKCE verifier from a previous (possibly interrupted) attempt,
    // so switching between providers always starts from a clean slate.
    try {
      Object.keys(window.localStorage).forEach(k => {
        if (k.includes('code-verifier') || k.includes('code_verifier')) {
          window.localStorage.removeItem(k);
        }
      });
    } catch (e) { /* ignore */ }
    const { error } = await supabase.auth.signInWithOAuth({
      provider,
      options: { redirectTo: window.location.origin },
    });
    if (error) { setError(error.message); setLoading(null); }
  }

  async function signInAsGuest() {
    setLoading('guest');
    setError('');
    const { error } = await supabase.auth.signInAnonymously();
    if (error) { setError(error.message); setLoading(null); }
  }

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-6" style={{ background: C.bg }}>
      <div className="w-full max-w-sm text-center">
        <div className="tt-display text-5xl mb-2" style={{ color: C.text }}>TT Smash</div>
        <p className="tt-body text-sm mb-10" style={{ color: C.dim }}>{t('auth_subtitle')}</p>
        <div className="flex flex-col gap-3">
          <button
            onClick={() => signInWithProvider('google')}
            disabled={loading !== null}
            className="tt-body w-full px-4 py-3 rounded-xl font-semibold flex items-center justify-center gap-2 disabled:opacity-50"
            style={{ background: '#fff', color: '#1a1a1a' }}
          >
            {t('auth_google')}
          </button>
          <button
            onClick={() => signInWithProvider('facebook')}
            disabled={loading !== null}
            className="tt-body w-full px-4 py-3 rounded-xl font-semibold flex items-center justify-center gap-2 disabled:opacity-50"
            style={{ background: '#1877F2', color: '#fff' }}
          >
            {t('auth_facebook')}
          </button>
          <button
            onClick={signInAsGuest}
            disabled={loading !== null}
            className="tt-body w-full px-4 py-3 rounded-xl font-semibold disabled:opacity-50"
            style={{ background: 'transparent', color: C.dim, border: `1px solid ${C.line}` }}
          >
            {t('auth_guest')}
          </button>
        </div>
        {error && <div className="tt-body text-xs mt-4" style={{ color: C.red }}>{error}</div>}
      </div>
    </div>
  );
}

