/* ============================= SETTINGS ============================= */
function SettingsScreen({ setView, settings, updateSettings, resetAllData }) {
  const { t } = useT();
  const [confirming, setConfirming] = useState(false);

  useEffect(() => {
    if (!confirming) return;
    const timer = setTimeout(() => setConfirming(false), 5000);
    return () => clearTimeout(timer);
  }, [confirming]);

  function handleDeleteClick() {
    if (confirming) {
      setConfirming(false);
      resetAllData();
    } else {
      setConfirming(true);
    }
  }

  return (
    <div>
      <BackBar title={t('settings_title')} onBack={() => setView('home')} />
      <div className="flex flex-col gap-4">
        <Panel>
          <ToggleRow
            label={t('settings_toss_label')}
            desc={t('settings_toss_desc')}
            value={settings.coinToss}
            onChange={v => updateSettings({ coinToss: v })}
          />
        </Panel>
        <Panel>
          <ToggleRow
            label={t('settings_voice_label')}
            desc={t('settings_voice_desc')}
            value={settings.voice}
            onChange={v => updateSettings({ voice: v })}
          />
        </Panel>
        <Panel>
          <ToggleRow
            label={t('settings_break_label')}
            desc={t('settings_break_desc')}
            value={settings.setBreaks}
            onChange={v => updateSettings({ setBreaks: v })}
          />
        </Panel>
        <Panel>
          <ToggleRow
            label={t('settings_point_sound_label')}
            desc={t('settings_point_sound_desc')}
            value={settings.pointSound}
            onChange={v => updateSettings({ pointSound: v })}
          />
        </Panel>
        <Panel>
          <ToggleRow
            label={t('settings_custom_sets_label')}
            desc={t('settings_custom_sets_desc')}
            value={settings.customSets}
            onChange={v => updateSettings({ customSets: v })}
          />
        </Panel>
        <div className="tt-body text-xs px-1" style={{ color: C.dim }}>
          {t('settings_footer')}
        </div>

        <Panel style={{ borderColor: C.red, marginTop: 8 }}>
          <div className="tt-body text-sm font-semibold mb-1" style={{ color: C.red }}>{t('settings_danger_zone')}</div>
          <div className="tt-body text-xs mb-3" style={{ color: C.dim }}>{t('settings_delete_all_desc')}</div>
          <button
            onClick={handleDeleteClick}
            className="tt-body w-full px-4 py-2.5 rounded-xl font-semibold transition-colors"
            style={{
              background: confirming ? C.red : 'transparent',
              color: confirming ? '#fff' : C.red,
              border: `1px solid ${C.red}`,
            }}
          >
            {confirming ? t('settings_delete_confirm') : t('settings_delete_all')}
          </button>
        </Panel>
      </div>
    </div>
  );
}

/* ============================= LEADERBOARD ============================= */
function Leaderboard({ setView, matchLog, photos, setPhotos, onSelectPlayer, friends, profile }) {
  const { t } = useT();
  const [scope, setScope] = useState('all');
  const scopedLog = scope === 'all' ? matchLog : matchLog.filter(m => m.kind === scope);
  const stats = aggregateStats(scopedLog);
  const names = stats.map(s => s.name);
  usePhotos(names, photos, setPhotos);

  const wonLabel = t('chart_won');
  const lostLabel = t('chart_lost');
  const forLabel = t('chart_for');
  const againstLabel = t('chart_against');

  const chartData = stats.slice(0, 10).map(s => ({ name: s.name.length > 8 ? s.name.slice(0, 7) + '…' : s.name, [wonLabel]: s.w, [lostLabel]: s.l }));
  const pointsData = stats.slice(0, 10).map(s => ({ name: s.name.length > 8 ? s.name.slice(0, 7) + '…' : s.name, [forLabel]: s.pointsFor, [againstLabel]: s.pointsAgainst }));

  return (
    <div>
      <BackBar title={t('stats_title')} onBack={() => setView('home')} />

      <Panel style={{ marginBottom: 16 }}>
        <SegButton
          options={[
            { value: 'all', label: t('stats_scope_all') },
            { value: 'competition', label: t('nav_competition') },
            { value: 'tournament', label: t('nav_tournament') },
          ]}
          value={scope}
          onChange={setScope}
        />
      </Panel>

      {stats.length === 0 ? (
        <Panel><div className="tt-body text-sm text-center" style={{ color: C.dim }}>{t('stats_empty')}</div></Panel>
      ) : (
        <>
          <GhostButton onClick={() => setView('h2h')} style={{ width: '100%', marginBottom: 16, textAlign: 'center' }}>
            <span className="flex items-center justify-center gap-2"><SwordsIcon size={15} /> {t('stats_h2h')}</span>
          </GhostButton>

          <Panel style={{ marginBottom: 16 }}>
            <div className="tt-body text-sm font-semibold mb-3" style={{ color: C.dim }}>{t('stats_ranking')}</div>
            <div className="flex flex-col gap-2">
              {stats.map((row, i) => {
                const rowStreak = computeStreaks(scopedLog, row.name).current;
                return (
                <button
                  key={row.name}
                  onClick={async () => {
                    let foundId = null;
                    try {
                      const { data } = await supabase.from('profiles').select('id').ilike('username', row.name).limit(1).maybeSingle();
                      if (data) foundId = data.id;
                    } catch (e) { /* best effort — falls back to guest-style name match */ }
                    onSelectPlayer(row.name, foundId);
                  }}
                  className="w-full flex items-center gap-3 p-2.5 rounded-xl text-left"
                  style={{ background: i === 0 ? C.panel2 : 'transparent', border: `1px solid ${C.line}` }}
                >
                  <span className="tt-display text-lg w-5 text-center flex-shrink-0" style={{ color: C.dim }}>{i + 1}</span>
                  <Avatar name={row.name} photo={resolvePhoto(row.name, photos, profile)} size={36} />
                  <div className="flex-1 min-w-0">
                    <div className="tt-body text-sm font-semibold truncate flex items-center gap-1" style={{ color: C.text }}>
                      {row.name}
                      {friends.includes(row.name) && <Star size={11} color={C.amber} fill={C.amber} />}
                      {rowStreak >= 2 && (
                        <span className="flex items-center gap-0.5 flex-shrink-0" style={{ color: C.amber }}>
                          <Flame size={11} color={C.amber} fill={C.amber} />
                          <span className="tt-body text-xs">{rowStreak}</span>
                        </span>
                      )}
                    </div>
                    <div className="tt-body text-xs truncate" style={{ color: C.dim }}>{row.setsFor}-{row.setsAgainst} {t('h2h_sets')} &bull; {row.pointsFor}-{row.pointsAgainst} {t('h2h_points')}</div>
                  </div>
                  <div className="text-right flex-shrink-0">
                    <div className="tt-display text-xl" style={{ color: C.greenLight }}>{row.w}{wonLabel.charAt(0)}</div>
                    <div className="tt-body text-xs" style={{ color: C.dim }}>{row.l}{lostLabel.charAt(0)}</div>
                  </div>
                </button>
                );
              })}
            </div>
          </Panel>

          <Panel style={{ marginBottom: 16 }}>
            <div className="tt-body text-sm font-semibold mb-3" style={{ color: C.dim }}>{t('stats_wins_chart')}</div>
            <div style={{ width: '100%', height: 220 }}>
              <ResponsiveContainer>
                <BarChart data={chartData} margin={{ top: 5, right: 5, left: -20, bottom: 25 }}>
                  <CartesianGrid strokeDasharray="3 3" stroke={C.line} />
                  <XAxis dataKey="name" tick={{ fill: C.dim, fontSize: 10 }} interval={0} angle={-25} textAnchor="end" height={45} />
                  <YAxis tick={{ fill: C.dim, fontSize: 11 }} allowDecimals={false} />
                  <Tooltip contentStyle={{ background: C.panel2, border: `1px solid ${C.line}`, borderRadius: 8, color: C.text }} />
                  <Bar dataKey={wonLabel} fill={C.greenLight} radius={[4, 4, 0, 0]} />
                  <Bar dataKey={lostLabel} fill={C.red} radius={[4, 4, 0, 0]} />
                </BarChart>
              </ResponsiveContainer>
            </div>
          </Panel>

          <Panel>
            <div className="tt-body text-sm font-semibold mb-3" style={{ color: C.dim }}>{t('stats_points_chart')}</div>
            <div style={{ width: '100%', height: 220 }}>
              <ResponsiveContainer>
                <BarChart data={pointsData} margin={{ top: 5, right: 5, left: -20, bottom: 25 }}>
                  <CartesianGrid strokeDasharray="3 3" stroke={C.line} />
                  <XAxis dataKey="name" tick={{ fill: C.dim, fontSize: 10 }} interval={0} angle={-25} textAnchor="end" height={45} />
                  <YAxis tick={{ fill: C.dim, fontSize: 11 }} allowDecimals={false} />
                  <Tooltip contentStyle={{ background: C.panel2, border: `1px solid ${C.line}`, borderRadius: 8, color: C.text }} />
                  <Bar dataKey={forLabel} fill={C.amber} radius={[4, 4, 0, 0]} />
                  <Bar dataKey={againstLabel} fill={C.panel2} stroke={C.line} radius={[4, 4, 0, 0]} />
                </BarChart>
              </ResponsiveContainer>
            </div>
          </Panel>
        </>
      )}
    </div>
  );
}

/* ============================= PLAYER DETAIL ============================= */
function PlayerDetail({ setView, playerName, playerProfileId, matchLog, photos, setPhotos, friends, toggleFriend, onChallenge, profile }) {
  const { t, lang } = useT();
  const stats = aggregateStats(matchLog);
  const me = stats.find(s => s.name === playerName);
  const myMatches = matchLog.filter(m => m.nameA === playerName || m.nameB === playerName);
  const fileRef = useRef(null);
  const [detailMatch, setDetailMatch] = useState(null);

  usePhotos([playerName], photos, setPhotos);

  async function handleFile(e) {
    const file = e.target.files && e.target.files[0];
    if (!file) return;
    try {
      const dataUrl = await resizeImage(file, 240);
      setPhotos(p => ({ ...p, [playerName]: dataUrl }));
      await window.storage.set(photoKey(playerName), dataUrl, false);
    } catch (err) { /* ignore failed upload */ }
  }

  if (!me) return (
    <div>
      <BackBar title={playerName} onBack={() => setView('leaderboard')} />
      <Panel style={{ marginBottom: 16 }}>
        <div className="tt-body text-sm mb-3" style={{ color: C.dim }}>{t('player_not_found')}</div>
        <PrimaryButton onClick={() => onChallenge(playerName, playerProfileId)} style={{ width: '100%' }}>
          <span className="flex items-center justify-center gap-2"><Swords size={15} /> {t('btn_challenge')}</span>
        </PrimaryButton>
      </Panel>
    </div>
  );

  const winPct = me.played > 0 ? Math.round((me.w / me.played) * 100) : 0;
  const serve = aggregateServeStats(matchLog, playerName);
  const hasServeData = serve.servePts + serve.returnPts > 0;
  const streaks = computeStreaks(matchLog, playerName);
  const playerBadges = computeBadges(matchLog, playerName, t);
  const playerTitle = getPlayerTitle(playerBadges.filter(b => b.earned).length, TOTAL_POSSIBLE_BADGES, playerName, lang, streaks.losing);
  function pct(won, total) { return total > 0 ? Math.round((won / total) * 100) : 0; }

  return (
    <div>
      <BackBar title={playerName} onBack={() => setView('leaderboard')} />

      <Panel style={{ marginBottom: 16 }}>
        <div className="flex items-center gap-4 mb-4">
          <Avatar name={playerName} photo={resolvePhoto(playerName, photos, profile)} size={64} />
          <div className="flex-1 min-w-0">
            <div className="tt-display text-2xl truncate" style={{ color: C.text }}>{playerName}</div>
            {playerTitle && <div className="tt-body text-xs font-semibold mb-0.5" style={{ color: C.amber }}>{playerTitle}</div>}
            <div className="tt-body text-xs" style={{ color: C.dim }}>{t('player_stats_line', { played: me.played, pct: winPct })}</div>
          </div>
          <button
            onClick={() => toggleFriend(playerName)}
            className="p-2 rounded-lg flex-shrink-0"
            style={{ background: friends.includes(playerName) ? C.amber : C.panel2 }}
            title={friends.includes(playerName) ? t('btn_remove_friend') : t('btn_add_friend')}
          >
            <Star size={18} color={friends.includes(playerName) ? '#241503' : C.dim} fill={friends.includes(playerName) ? '#241503' : 'none'} />
          </button>
        </div>
        <PrimaryButton onClick={() => onChallenge(playerName, playerProfileId)} style={{ width: '100%', marginBottom: 8 }}>
          <span className="flex items-center justify-center gap-2"><Swords size={15} /> {t('btn_challenge')}</span>
        </PrimaryButton>
        <input ref={fileRef} type="file" accept="image/*" style={{ display: 'none' }} onChange={handleFile} />
        <GhostButton onClick={() => fileRef.current && fileRef.current.click()} style={{ width: '100%', textAlign: 'center' }}>
          <span className="flex items-center justify-center gap-2"><Camera size={15} /> {resolvePhoto(playerName, photos, profile) ? t('player_photo_change') : t('player_photo_upload')}</span>
        </GhostButton>
      </Panel>

      <div className="grid grid-cols-2 gap-3 mb-4">
        <Panel style={{ textAlign: 'center' }}>
          <div className="tt-display text-3xl" style={{ color: C.greenLight }}>{me.w}</div>
          <div className="tt-body text-xs" style={{ color: C.dim }}>{t('player_won')}</div>
        </Panel>
        <Panel style={{ textAlign: 'center' }}>
          <div className="tt-display text-3xl" style={{ color: C.red }}>{me.l}</div>
          <div className="tt-body text-xs" style={{ color: C.dim }}>{t('player_lost')}</div>
        </Panel>
        <Panel style={{ textAlign: 'center' }}>
          <div className="tt-display text-2xl" style={{ color: C.text }}>{me.setsFor}-{me.setsAgainst}</div>
          <div className="tt-body text-xs" style={{ color: C.dim }}>{t('player_sets_label')}</div>
        </Panel>
        <Panel style={{ textAlign: 'center' }}>
          <div className="tt-display text-2xl" style={{ color: C.text }}>{me.pointsFor}-{me.pointsAgainst}</div>
          <div className="tt-body text-xs" style={{ color: C.dim }}>{t('player_points_label')}</div>
        </Panel>
        <Panel style={{ textAlign: 'center' }}>
          <div className="tt-display text-3xl flex items-center justify-center gap-1" style={{ color: C.amber }}>
            {streaks.current > 0 && <Flame size={20} color={C.amber} fill={C.amber} />}{streaks.current}
          </div>
          <div className="tt-body text-xs" style={{ color: C.dim }}>{t('streak_current')}</div>
        </Panel>
        <Panel style={{ textAlign: 'center' }}>
          <div className="tt-display text-3xl" style={{ color: C.text }}>{streaks.best}</div>
          <div className="tt-body text-xs" style={{ color: C.dim }}>{t('streak_best')}</div>
        </Panel>
        <Panel style={{ textAlign: 'center', gridColumn: 'span 2' }}>
          <div className="tt-display text-3xl" style={{ color: C.greenLight }}>{me.pointsFor}</div>
          <div className="tt-body text-xs" style={{ color: C.dim }}>{t('player_career_points_label')}</div>
        </Panel>
      </div>

      {hasServeData && (
        <Panel style={{ marginBottom: 16 }}>
          <div className="tt-body text-sm font-semibold mb-3" style={{ color: C.dim }}>{t('serve_stats_title')}</div>
          <div className="grid grid-cols-2 gap-3 text-center">
            <div>
              <div className="tt-display text-2xl" style={{ color: C.amber }}>{pct(serve.serveWon, serve.servePts)}%</div>
              <div className="tt-body text-xs" style={{ color: C.dim }}>{t('own_serve_label')} ({serve.serveWon}/{serve.servePts})</div>
            </div>
            <div>
              <div className="tt-display text-2xl" style={{ color: C.greenLight }}>{pct(serve.returnWon, serve.returnPts)}%</div>
              <div className="tt-body text-xs" style={{ color: C.dim }}>{t('return_label')} ({serve.returnWon}/{serve.returnPts})</div>
            </div>
          </div>
        </Panel>
      )}

      <Panel style={{ marginBottom: 16 }}>
        <div className="tt-body text-sm font-semibold mb-3 flex items-center gap-2" style={{ color: C.dim }}>
          <Award size={16} color={C.dim} /> {t('profile_badges_title')}
        </div>
        <BadgesGrid badges={playerBadges} />
      </Panel>

      <div className="tt-body text-sm font-semibold mb-2" style={{ color: C.dim }}>{t('player_recent')}</div>
      <div className="flex flex-col gap-2">
        {myMatches.slice(0, 10).map(m => {
          const opponent = m.nameA === playerName ? m.nameB : m.nameA;
          const won = m.winner === playerName;
          const myScore = m.nameA === playerName ? m.setsA : m.setsB;
          const oppScore = m.nameA === playerName ? m.setsB : m.setsA;
          return (
            <button key={m.id} onClick={() => setDetailMatch(m)} className="rounded-xl p-3 flex justify-between items-center w-full text-left" style={{ background: C.panel, border: `1px solid ${C.line}` }}>
              <div className="min-w-0">
                <div className="tt-body text-sm truncate" style={{ color: C.text }}>{t('vs_label', { name: opponent })}</div>
                <div className="tt-body text-xs" style={{ color: C.dim }}>{getModeLabel(m, t)}</div>
              </div>
              <span className="tt-body text-xs px-2 py-1 rounded-md flex-shrink-0" style={{ background: won ? C.green : C.red, color: '#fff' }}>
                {won ? t('player_won').charAt(0) : t('player_lost').charAt(0)} {myScore}-{oppScore}
              </span>
            </button>
          );
        })}
        {myMatches.length === 0 && <div className="tt-body text-sm" style={{ color: C.dim }}>{t('player_none')}</div>}
      </div>

      {detailMatch && <MatchDetailModal match={detailMatch} onClose={() => setDetailMatch(null)} />}
    </div>
  );
}

/* ============================= HEAD TO HEAD ============================= */
function HeadToHead({ setView, matchLog, photos, setPhotos, profile }) {
  const { t } = useT();
  const names = aggregateStats(matchLog).map(s => s.name);
  const [playerA, setPlayerA] = useState(names[0] || '');
  const [playerB, setPlayerB] = useState(names[1] || names[0] || '');
  const [detailMatch, setDetailMatch] = useState(null);
  usePhotos([playerA, playerB].filter(Boolean), photos, setPhotos);

  const h2hMatches = matchLog.filter(m =>
    (m.nameA === playerA && m.nameB === playerB) || (m.nameA === playerB && m.nameB === playerA)
  );

  let aWins = 0, bWins = 0, aSets = 0, bSets = 0, aPoints = 0, bPoints = 0;
  h2hMatches.forEach(m => {
    const aIsA = m.nameA === playerA;
    const sA = aIsA ? m.setsA : m.setsB;
    const sB = aIsA ? m.setsB : m.setsA;
    const pA = aIsA ? (m.totalPointsA || 0) : (m.totalPointsB || 0);
    const pB = aIsA ? (m.totalPointsB || 0) : (m.totalPointsA || 0);
    aSets += sA; bSets += sB; aPoints += pA; bPoints += pB;
    if (m.winner === playerA) aWins++; else if (m.winner === playerB) bWins++;
  });

  const selectStyle = { background: C.panel2, border: `1px solid ${C.line}`, color: C.text };

  return (
    <div>
      <BackBar title={t('h2h_title')} onBack={() => setView('leaderboard')} />

      {names.length < 2 ? (
        <Panel><div className="tt-body text-sm" style={{ color: C.dim }}>{t('h2h_need_two')}</div></Panel>
      ) : (
        <>
          <Panel style={{ marginBottom: 16 }}>
            <div className="grid grid-cols-2 gap-3">
              <select value={playerA} onChange={e => setPlayerA(e.target.value)} className="tt-body px-3 py-2 rounded-lg" style={selectStyle}>
                {names.map(n => <option key={n} value={n}>{n}</option>)}
              </select>
              <select value={playerB} onChange={e => setPlayerB(e.target.value)} className="tt-body px-3 py-2 rounded-lg" style={selectStyle}>
                {names.map(n => <option key={n} value={n}>{n}</option>)}
              </select>
            </div>
          </Panel>

          {playerA === playerB ? (
            <Panel><div className="tt-body text-sm" style={{ color: C.dim }}>{t('h2h_pick_two')}</div></Panel>
          ) : (
            <>
              <Panel style={{ marginBottom: 16 }}>
                <div className="grid grid-cols-2 gap-4 text-center mb-4">
                  <div>
                    <Avatar name={playerA} photo={resolvePhoto(playerA, photos, profile)} size={56} />
                    <div className="tt-body text-sm font-semibold mt-2 truncate" style={{ color: C.text }}>{playerA}</div>
                    <div className="tt-display text-4xl mt-1" style={{ color: C.greenLight }}>{aWins}</div>
                  </div>
                  <div>
                    <Avatar name={playerB} photo={resolvePhoto(playerB, photos, profile)} size={56} />
                    <div className="tt-body text-sm font-semibold mt-2 truncate" style={{ color: C.text }}>{playerB}</div>
                    <div className="tt-display text-4xl mt-1" style={{ color: C.greenLight }}>{bWins}</div>
                  </div>
                </div>
                <div className="tt-body text-xs text-center" style={{ color: C.dim }}>
                  {t('h2h_count', { n: h2hMatches.length })} &bull; {t('h2h_sets')} {aSets}-{bSets} &bull; {t('h2h_points')} {aPoints}-{bPoints}
                </div>
              </Panel>

              <div className="tt-body text-sm font-semibold mb-2" style={{ color: C.dim }}>{t('h2h_history')}</div>
              <div className="flex flex-col gap-2">
                {h2hMatches.length === 0 && <div className="tt-body text-sm" style={{ color: C.dim }}>{t('h2h_none')}</div>}
                {h2hMatches.map(m => (
                  <button key={m.id} onClick={() => setDetailMatch(m)} className="rounded-xl p-3 w-full text-left" style={{ background: C.panel, border: `1px solid ${C.line}` }}>
                    <div className="tt-body text-xs mb-1" style={{ color: C.dim }}>
                      {getModeLabel(m, t)} &bull; {new Date(m.timestamp).toLocaleDateString()}
                    </div>
                    <div className="tt-body text-sm" style={{ color: C.text }}>{t('h2h_wins', { name: m.winner, a: Math.max(m.setsA, m.setsB), b: Math.min(m.setsA, m.setsB) })}</div>
                  </button>
                ))}
              </div>
            </>
          )}
        </>
      )}
      {detailMatch && <MatchDetailModal match={detailMatch} onClose={() => setDetailMatch(null)} />}
    </div>
  );
}

/* ============================= FRIENDS ============================= */
function PlayerPicker({ value, onChange, placeholder, friendsList, myProfileId }) {
  const { t } = useT();
  const [query, setQuery] = useState(value && value.name ? value.name : '');
  const [results, setResults] = useState([]);
  const [searching, setSearching] = useState(false);
  const [focused, setFocused] = useState(false);

  useEffect(() => {
    const q = query.trim();
    if (!q) { setResults([]); return; }
    setSearching(true);
    const timer = setTimeout(async () => {
      try {
        const { data } = await supabase
          .from('profiles')
          .select('id, username, avatar_url')
          .ilike('username', `%${q}%`)
          .neq('id', myProfileId || '')
          .limit(8);
        setResults(data || []);
      } catch (e) { setResults([]); }
      setSearching(false);
    }, 250);
    return () => clearTimeout(timer);
  }, [query, myProfileId]);

  function selectProfile(p) {
    setQuery(p.username);
    setResults([]);
    setFocused(false);
    onChange({ profileId: p.id, name: p.username, avatar_url: p.avatar_url });
  }

  function handleTextChange(v) {
    setQuery(v);
    onChange({ profileId: null, name: v });
  }

  const shownFriends = friendsList.filter(f => !query.trim() || f.username.toLowerCase().includes(query.trim().toLowerCase()));

  return (
    <div className="relative">
      <input
        value={query}
        onChange={e => handleTextChange(e.target.value)}
        onFocus={() => setFocused(true)}
        onBlur={() => setTimeout(() => setFocused(false), 150)}
        placeholder={placeholder}
        className="tt-body w-full px-3 py-2 rounded-lg outline-none"
        style={{ background: C.panel2, border: `1px solid ${C.line}`, color: C.text }}
      />
      {focused && !query.trim() && shownFriends.length > 0 && (
        <div className="flex gap-2 flex-wrap mt-2">
          {shownFriends.map(f => (
            <button key={f.id} onMouseDown={() => selectProfile(f)} className="flex items-center gap-1.5 px-2 py-1 rounded-full flex-shrink-0" style={{ background: C.panel2, border: `1px solid ${C.line}` }}>
              <Avatar name={f.username} photo={f.avatar_url} size={20} />
              <span className="tt-body text-xs" style={{ color: C.text }}>{f.username}</span>
            </button>
          ))}
        </div>
      )}
      {focused && query.trim() && results.length > 0 && (
        <div className="absolute z-10 w-full mt-1 rounded-lg overflow-hidden" style={{ background: C.panel2, border: `1px solid ${C.line}` }}>
          {results.map(p => (
            <button key={p.id} onMouseDown={() => selectProfile(p)} className="w-full flex items-center gap-2 px-3 py-2 text-left" style={{ borderBottom: `1px solid ${C.line}` }}>
              <Avatar name={p.username} photo={p.avatar_url} size={24} />
              <span className="tt-body text-sm" style={{ color: C.text }}>{p.username}</span>
            </button>
          ))}
        </div>
      )}
    </div>
  );
}

function GroupsScreen({ setView, session, onSelectGroup, profile }) {
  const { t } = useT();
  const myId = session && session.user ? session.user.id : null;
  const [myGroups, setMyGroups] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showCreate, setShowCreate] = useState(false);
  const [createName, setCreateName] = useState('');
  const [createDesc, setCreateDesc] = useState('');
  const [creating, setCreating] = useState(false);
  const [query, setQuery] = useState('');
  const [results, setResults] = useState([]);
  const [searching, setSearching] = useState(false);
  const [pendingRequestIds, setPendingRequestIds] = useState(new Set());
  const [nearbyGroups, setNearbyGroups] = useState([]);
  const [myInvites, setMyInvites] = useState([]);

  async function loadMyGroups() {
    setLoading(true);
    try {
      const { data } = await supabase
        .from('club_members')
        .select('role, status, clubs(id, name, description, city, country)')
        .eq('user_id', myId);
      const rows = data || [];
      setMyGroups(rows.filter(r => r.clubs && r.status === 'approved').map(r => ({ ...r.clubs, role: r.role })));
      setPendingRequestIds(new Set(rows.filter(r => r.clubs && r.status === 'pending').map(r => r.clubs.id)));
      setMyInvites(rows.filter(r => r.clubs && r.status === 'invited').map(r => r.clubs));
    } catch (e) { /* best effort */ }
    setLoading(false);
  }

  useEffect(() => { if (myId) loadMyGroups(); }, [myId]);

  useEffect(() => {
    if (!profile || !(profile.city || profile.country)) { setNearbyGroups([]); return; }
    (async () => {
      try {
        let q = supabase.from('clubs').select('id, name, description, city, country');
        if (profile.city) q = q.ilike('city', profile.city);
        else if (profile.country) q = q.ilike('country', profile.country);
        const { data } = await q.limit(10);
        setNearbyGroups(data || []);
      } catch (e) { setNearbyGroups([]); }
    })();
  }, [profile && profile.city, profile && profile.country]);

  useEffect(() => {
    const q = query.trim();
    if (!q) { setResults([]); return; }
    setSearching(true);
    const timer = setTimeout(async () => {
      try {
        const { data } = await supabase.from('clubs').select('id, name, description, city, country').ilike('name', `%${q}%`).limit(20);
        setResults(data || []);
      } catch (e) { setResults([]); }
      setSearching(false);
    }, 300);
    return () => clearTimeout(timer);
  }, [query]);

  async function createGroup() {
    const name = createName.trim();
    if (!name || creating) return;
    setCreating(true);
    try {
      const { error } = await supabase.from('clubs').insert({
        name, description: createDesc.trim() || null, created_by: myId,
      }).select().single();
      if (!error) {
        setCreateName(''); setCreateDesc(''); setShowCreate(false);
        await loadMyGroups();
      }
    } catch (e) { /* best effort */ }
    setCreating(false);
  }

  async function joinGroup(clubId) {
    try {
      await supabase.from('club_members').insert({ club_id: clubId, user_id: myId, role: 'member', status: 'pending' });
      setPendingRequestIds(prev => new Set(prev).add(clubId));
    } catch (e) { /* best effort */ }
  }

  async function acceptInvite(clubId) {
    try {
      await supabase.from('club_members').update({ status: 'approved' }).eq('club_id', clubId).eq('user_id', myId);
      await loadMyGroups();
    } catch (e) { /* best effort */ }
  }

  async function declineInvite(clubId) {
    try {
      await supabase.from('club_members').delete().eq('club_id', clubId).eq('user_id', myId);
      await loadMyGroups();
    } catch (e) { /* best effort */ }
  }

  const myGroupIds = new Set(myGroups.map(g => g.id));

  return (
    <div>
      <BackBar title={t('nav_groups')} onBack={() => setView('home')} />

      {myInvites.length > 0 && (
        <Panel style={{ marginBottom: 16 }}>
          <div className="tt-body text-sm font-semibold mb-3" style={{ color: C.dim }}>{t('group_invites_title')}</div>
          <div className="flex flex-col gap-2">
            {myInvites.map(g => (
              <div key={g.id} className="flex items-center gap-3">
                <div className="tt-body text-sm font-semibold flex-1 min-w-0 truncate" style={{ color: C.text }}>{g.name}</div>
                <button onClick={() => acceptInvite(g.id)} className="p-2 rounded-lg flex-shrink-0" style={{ background: C.greenLight }}>
                  <Check size={16} color="#04140D" />
                </button>
                <button onClick={() => declineInvite(g.id)} className="p-2 rounded-lg flex-shrink-0" style={{ background: C.panel2 }}>
                  <X size={16} color={C.dim} />
                </button>
              </div>
            ))}
          </div>
        </Panel>
      )}

      <Panel style={{ marginBottom: 16 }}>
        <input
          value={query}
          onChange={e => setQuery(e.target.value)}
          placeholder={t('groups_search_placeholder')}
          className="tt-body w-full px-3 py-2 rounded-lg outline-none"
          style={{ background: C.panel2, border: `1px solid ${C.line}`, color: C.text }}
        />
      </Panel>

      {query.trim() && (
        <Panel style={{ marginBottom: 16 }}>
          {searching ? (
            <div className="tt-body text-sm text-center" style={{ color: C.dim }}>...</div>
          ) : results.length === 0 ? (
            <div className="tt-body text-sm text-center" style={{ color: C.dim }}>{t('group_no_results')}</div>
          ) : (
            <div className="flex flex-col gap-2">
              {results.map(g => (
                <div key={g.id} className="flex items-center gap-3">
                  <div className="flex-1 min-w-0">
                    <div className="tt-body text-sm font-semibold truncate" style={{ color: C.text }}>{g.name}</div>
                    {(g.city || g.country) && <div className="tt-body text-xs truncate" style={{ color: C.dim }}>{[g.city, g.country].filter(Boolean).join(', ')}</div>}
                  </div>
                  {myGroupIds.has(g.id) ? (
                    <span className="tt-body text-xs flex-shrink-0" style={{ color: C.dim }}>{t('group_joined_label')}</span>
                  ) : pendingRequestIds.has(g.id) ? (
                    <span className="tt-body text-xs flex-shrink-0" style={{ color: C.amber }}>{t('group_request_sent')}</span>
                  ) : (
                    <button onClick={() => joinGroup(g.id)} className="tt-body text-xs px-3 py-2 rounded-lg flex-shrink-0" style={{ background: C.greenLight, color: '#04140D' }}>
                      {t('group_join_button')}
                    </button>
                  )}
                </div>
              ))}
            </div>
          )}
        </Panel>
      )}

      {!query.trim() && nearbyGroups.length > 0 && (
        <Panel style={{ marginBottom: 16 }}>
          <div className="tt-body text-sm font-semibold mb-3" style={{ color: C.dim }}>{t('groups_nearby_title')}</div>
          <div className="flex flex-col gap-2">
            {nearbyGroups.map(g => (
              <div key={g.id} className="flex items-center gap-3">
                <div className="flex-1 min-w-0">
                  <div className="tt-body text-sm font-semibold truncate" style={{ color: C.text }}>{g.name}</div>
                  {(g.city || g.country) && <div className="tt-body text-xs truncate" style={{ color: C.dim }}>{[g.city, g.country].filter(Boolean).join(', ')}</div>}
                </div>
                {myGroupIds.has(g.id) ? (
                  <span className="tt-body text-xs flex-shrink-0" style={{ color: C.dim }}>{t('group_joined_label')}</span>
                ) : pendingRequestIds.has(g.id) ? (
                  <span className="tt-body text-xs flex-shrink-0" style={{ color: C.amber }}>{t('group_request_sent')}</span>
                ) : (
                  <button onClick={() => joinGroup(g.id)} className="tt-body text-xs px-3 py-2 rounded-lg flex-shrink-0" style={{ background: C.greenLight, color: '#04140D' }}>
                    {t('group_join_button')}
                  </button>
                )}
              </div>
            ))}
          </div>
        </Panel>
      )}

      {!showCreate ? (
        <GhostButton onClick={() => setShowCreate(true)} style={{ width: '100%', textAlign: 'center', marginBottom: 16 }}>
          <span className="flex items-center justify-center gap-2"><Plus size={15} /> {t('groups_create_button')}</span>
        </GhostButton>
      ) : (
        <Panel style={{ marginBottom: 16 }}>
          <input
            value={createName}
            onChange={e => setCreateName(e.target.value)}
            placeholder={t('group_name_placeholder')}
            className="tt-body w-full px-3 py-2 rounded-lg outline-none mb-2"
            style={{ background: C.panel2, border: `1px solid ${C.line}`, color: C.text }}
          />
          <input
            value={createDesc}
            onChange={e => setCreateDesc(e.target.value)}
            placeholder={t('group_description_placeholder')}
            className="tt-body w-full px-3 py-2 rounded-lg outline-none mb-3"
            style={{ background: C.panel2, border: `1px solid ${C.line}`, color: C.text }}
          />
          <PrimaryButton onClick={createGroup} disabled={creating || !createName.trim()} style={{ width: '100%' }}>
            {t('groups_create_button')}
          </PrimaryButton>
        </Panel>
      )}

      <div className="tt-body text-sm font-semibold mb-2 px-1" style={{ color: C.dim }}>{t('nav_groups')}</div>
      {!loading && myGroups.length === 0 ? (
        <Panel><div className="tt-body text-sm text-center" style={{ color: C.dim }}>{t('groups_empty')}</div></Panel>
      ) : (
        <div className="flex flex-col gap-2">
          {myGroups.map(g => (
            <button
              key={g.id}
              onClick={() => onSelectGroup(g.id, g.name)}
              className="w-full rounded-xl p-3 flex items-center gap-3 text-left"
              style={{ background: C.panel, border: `1px solid ${C.line}` }}
            >
              <div className="p-2 rounded-lg flex-shrink-0" style={{ background: C.panel2 }}><Building2 size={18} color={C.amber} /></div>
              <div className="min-w-0 flex-1">
                <div className="tt-body text-sm font-semibold truncate" style={{ color: C.text }}>{g.name}</div>
                {(g.city || g.country) && <div className="tt-body text-xs truncate" style={{ color: C.dim }}>{[g.city, g.country].filter(Boolean).join(', ')}</div>}
              </div>
            </button>
          ))}
        </div>
      )}
    </div>
  );
}

function GroupDetailScreen({ setView, groupId, groupName, session, matchLog, onSelectPlayer }) {
  const { t } = useT();
  const myId = session && session.user ? session.user.id : null;
  const [group, setGroup] = useState(null);
  const [members, setMembers] = useState([]);
  const [pendingRequests, setPendingRequests] = useState([]);
  const [myRole, setMyRole] = useState(null);
  const [loading, setLoading] = useState(true);
  const [invitePick, setInvitePick] = useState(null);
  const friendsListForInvite = useFriendsList(myId);

  async function sendInvite(target) {
    if (!target || !target.profileId) return;
    try {
      await supabase.from('club_members').insert({ club_id: groupId, user_id: target.profileId, role: 'member', status: 'invited' });
      await loadGroup();
    } catch (e) { /* best effort */ }
    setInvitePick(null);
  }

  async function loadGroup() {
    try {
      const { data: clubData } = await supabase.from('clubs').select('*').eq('id', groupId).maybeSingle();
      setGroup(clubData || null);
      const { data: rows } = await supabase
        .from('club_members')
        .select('user_id, role, status, profiles(id, username, avatar_url)')
        .eq('club_id', groupId);
      const all = (rows || []).filter(r => r.profiles);
      setMembers(all.filter(r => r.status === 'approved').map(r => ({ ...r.profiles, role: r.role })));
      setPendingRequests(all.filter(r => r.status === 'pending').map(r => ({ ...r.profiles, memberRowUserId: r.user_id })));
      const mine = all.find(r => r.user_id === myId);
      setMyRole(mine ? mine.role : null);
    } catch (e) { /* best effort */ }
    setLoading(false);
  }

  useEffect(() => { if (groupId) loadGroup(); }, [groupId]);

  async function leaveGroup() {
    try {
      await supabase.from('club_members').delete().eq('club_id', groupId).eq('user_id', myId);
    } catch (e) { /* best effort */ }
    setView('groups');
  }

  async function approveRequest(userId) {
    try {
      await supabase.from('club_members').update({ status: 'approved' }).eq('club_id', groupId).eq('user_id', userId);
      await loadGroup();
    } catch (e) { /* best effort */ }
  }

  async function declineRequest(userId) {
    try {
      await supabase.from('club_members').delete().eq('club_id', groupId).eq('user_id', userId);
      await loadGroup();
    } catch (e) { /* best effort */ }
  }

  async function removeMember(userId) {
    try {
      await supabase.from('club_members').delete().eq('club_id', groupId).eq('user_id', userId);
      await loadGroup();
    } catch (e) { /* best effort */ }
  }

  const isAdmin = myRole === 'admin';
  const memberPhotoByName = {};
  members.forEach(m => { memberPhotoByName[(m.username || '').trim().toLowerCase()] = m.avatar_url; });
  const memberNames = new Set(members.map(m => (m.username || '').trim().toLowerCase()));
  const groupMatches = matchLog.filter(m =>
    memberNames.has((m.nameA || '').trim().toLowerCase()) && memberNames.has((m.nameB || '').trim().toLowerCase())
  );
  const stats = aggregateStats(groupMatches).sort((a, b) => b.w - a.w);

  return (
    <div>
      <BackBar title={group ? group.name : groupName || ''} onBack={() => setView('groups')} />

      {group && group.description && (
        <Panel style={{ marginBottom: 16 }}>
          <div className="tt-body text-sm" style={{ color: C.dim }}>{group.description}</div>
        </Panel>
      )}

      {isAdmin && (
        <Panel style={{ marginBottom: 16 }}>
          <div className="tt-body text-sm font-semibold mb-3" style={{ color: C.dim }}>{t('group_invite_section_title')}</div>
          <PlayerPicker
            value={invitePick}
            onChange={p => { setInvitePick(p); if (p && p.profileId) sendInvite(p); }}
            placeholder={t('friends_search_placeholder')}
            friendsList={friendsListForInvite}
            myProfileId={myId}
          />
        </Panel>
      )}

      {isAdmin && pendingRequests.length > 0 && (
        <Panel style={{ marginBottom: 16 }}>
          <div className="tt-body text-sm font-semibold mb-3" style={{ color: C.dim }}>{t('group_pending_requests_title')}</div>
          <div className="flex flex-col gap-2">
            {pendingRequests.map(r => (
              <div key={r.memberRowUserId} className="flex items-center gap-3">
                <Avatar name={r.username} photo={r.avatar_url} size={36} />
                <div className="tt-body text-sm font-semibold flex-1 min-w-0 truncate" style={{ color: C.text }}>{r.username}</div>
                <button onClick={() => approveRequest(r.memberRowUserId)} className="p-2 rounded-lg flex-shrink-0" style={{ background: C.greenLight }}>
                  <Check size={16} color="#04140D" />
                </button>
                <button onClick={() => declineRequest(r.memberRowUserId)} className="p-2 rounded-lg flex-shrink-0" style={{ background: C.panel2 }}>
                  <X size={16} color={C.dim} />
                </button>
              </div>
            ))}
          </div>
        </Panel>
      )}

      <Panel style={{ marginBottom: 16 }}>
        <div className="tt-body text-sm font-semibold mb-3" style={{ color: C.dim }}>{t('group_members_title')} ({members.length})</div>
        <div className="flex flex-col gap-2">
          {members.map(m => (
            <div key={m.id} className="flex items-center gap-3">
              <button onClick={() => onSelectPlayer(m.username, m.id)} className="flex items-center gap-3 flex-1 min-w-0 text-left">
                <Avatar name={m.username} photo={m.avatar_url} size={36} />
                <span className="tt-body text-sm font-semibold truncate" style={{ color: C.text }}>{m.username}</span>
                {m.role === 'admin' && <Star size={12} color={C.amber} fill={C.amber} />}
              </button>
              {isAdmin && m.id !== myId && (
                <button onClick={() => removeMember(m.id)} className="tt-body text-xs px-2 py-1.5 rounded-lg flex-shrink-0" style={{ background: C.panel2, color: C.red }}>
                  {t('group_remove_member')}
                </button>
              )}
            </div>
          ))}
        </div>
      </Panel>

      <Panel style={{ marginBottom: 16 }}>
        <div className="tt-body text-sm font-semibold mb-3" style={{ color: C.dim }}>{t('group_leaderboard_title')}</div>
        {!loading && stats.length === 0 ? (
          <div className="tt-body text-sm text-center" style={{ color: C.dim }}>{t('friends_no_results')}</div>
        ) : (
          <div className="flex flex-col gap-2">
            {stats.map((row, i) => (
              <button key={row.name} onClick={() => onSelectPlayer(row.name)} className="w-full flex items-center gap-3 p-2.5 rounded-xl text-left" style={{ background: i === 0 ? C.panel2 : 'transparent', border: `1px solid ${C.line}` }}>
                <span className="tt-display text-lg w-6 text-center flex-shrink-0" style={{ color: C.dim }}>{i + 1}</span>
                <Avatar name={row.name} photo={memberPhotoByName[row.name.trim().toLowerCase()]} size={32} />
                <div className="tt-body text-sm font-semibold flex-1 truncate" style={{ color: C.text }}>{row.name}</div>
                <div className="tt-body text-xs flex-shrink-0" style={{ color: C.dim }}>{row.w}{t('player_won').charAt(0).toLowerCase()}-{row.l}{t('player_lost').charAt(0).toLowerCase()}</div>
              </button>
            ))}
          </div>
        )}
      </Panel>

      <GhostButton onClick={leaveGroup} style={{ width: '100%', textAlign: 'center', color: C.red }}>
        {t('group_leave_button')}
      </GhostButton>
    </div>
  );
}

function FriendsScreen({ setView, session, onSelectPlayer }) {
  const { t } = useT();
  const myId = session.user.id;
  const [query, setQuery] = useState('');
  const [searchResults, setSearchResults] = useState([]);
  const [searching, setSearching] = useState(false);
  const [relationships, setRelationships] = useState([]);
  const [profilesById, setProfilesById] = useState({});
  const [loading, setLoading] = useState(true);

  async function loadRelationships() {
    try {
      const { data } = await supabase
        .from('friendships')
        .select('*')
        .or(`requester_id.eq.${myId},addressee_id.eq.${myId}`);
      const rels = data || [];
      setRelationships(rels);
      const otherIds = Array.from(new Set(rels.map(r => (r.requester_id === myId ? r.addressee_id : r.requester_id))));
      if (otherIds.length) {
        const { data: profs } = await supabase.from('profiles').select('*').in('id', otherIds);
        const map = {};
        (profs || []).forEach(p => { map[p.id] = p; });
        setProfilesById(map);
      }
    } catch (e) { /* best effort */ }
    setLoading(false);
  }

  useEffect(() => { loadRelationships(); }, []);

  useEffect(() => {
    const q = query.trim();
    if (!q) { setSearchResults([]); return; }
    setSearching(true);
    const timer = setTimeout(async () => {
      try {
        const { data } = await supabase
          .from('profiles')
          .select('*')
          .ilike('username', `%${q}%`)
          .neq('id', myId)
          .limit(20);
        setSearchResults(data || []);
      } catch (e) { setSearchResults([]); }
      setSearching(false);
    }, 300);
    return () => clearTimeout(timer);
  }, [query, myId]);

  function relationshipWith(otherId) {
    return relationships.find(r => r.requester_id === otherId || r.addressee_id === otherId);
  }

  async function sendRequest(otherId) {
    try {
      await supabase.from('friendships').insert({ requester_id: myId, addressee_id: otherId, status: 'pending' });
    } catch (e) { /* best effort */ }
    loadRelationships();
  }

  async function respondRequest(rel, accept) {
    try {
      if (accept) await supabase.from('friendships').update({ status: 'accepted' }).eq('id', rel.id);
      else await supabase.from('friendships').delete().eq('id', rel.id);
    } catch (e) { /* best effort */ }
    loadRelationships();
  }

  async function removeFriend(rel) {
    try { await supabase.from('friendships').delete().eq('id', rel.id); } catch (e) { /* best effort */ }
    loadRelationships();
  }

  const incoming = relationships.filter(r => r.status === 'pending' && r.addressee_id === myId);
  const accepted = relationships.filter(r => r.status === 'accepted');

  return (
    <div>
      <BackBar title={t('nav_friends')} onBack={() => setView('home')} />

      <Panel style={{ marginBottom: 16 }}>
        <input
          value={query}
          onChange={e => setQuery(e.target.value)}
          placeholder={t('friends_search_placeholder')}
          className="tt-body w-full px-3 py-2 rounded-lg outline-none"
          style={{ background: C.panel2, border: `1px solid ${C.line}`, color: C.text }}
        />
      </Panel>

      {query.trim() && (
        <Panel style={{ marginBottom: 16 }}>
          {searching ? (
            <div className="tt-body text-sm text-center" style={{ color: C.dim }}>...</div>
          ) : searchResults.length === 0 ? (
            <div className="tt-body text-sm text-center" style={{ color: C.dim }}>{t('friends_no_results')}</div>
          ) : (
            <div className="flex flex-col gap-2">
              {searchResults.map(p => {
                const rel = relationshipWith(p.id);
                return (
                  <div key={p.id} className="flex items-center gap-3">
                    <button onClick={() => onSelectPlayer(p.username, p.id)} className="flex items-center gap-3 flex-1 min-w-0 text-left">
                      <Avatar name={p.username} photo={p.avatar_url} size={40} />
                      <div className="tt-body text-sm font-semibold truncate" style={{ color: C.text }}>{p.username}</div>
                    </button>
                    {!rel && (
                      <button onClick={() => sendRequest(p.id)} className="tt-body text-xs px-3 py-2 rounded-lg flex-shrink-0" style={{ background: C.greenLight, color: '#04140D' }}>
                        {t('btn_add_friend')}
                      </button>
                    )}
                    {rel && rel.status === 'pending' && rel.requester_id === myId && (
                      <span className="tt-body text-xs flex-shrink-0" style={{ color: C.dim }}>{t('friend_request_sent')}</span>
                    )}
                    {rel && rel.status === 'pending' && rel.addressee_id === myId && (
                      <span className="tt-body text-xs flex-shrink-0" style={{ color: C.amber }}>{t('friend_request_pending_you')}</span>
                    )}
                    {rel && rel.status === 'accepted' && (
                      <span className="tt-body text-xs flex items-center gap-1 flex-shrink-0" style={{ color: C.dim }}>
                        <Star size={12} color={C.amber} fill={C.amber} /> {t('friends_already')}
                      </span>
                    )}
                  </div>
                );
              })}
            </div>
          )}
        </Panel>
      )}

      {incoming.length > 0 && (
        <Panel style={{ marginBottom: 16 }}>
          <div className="tt-body text-sm font-semibold mb-3" style={{ color: C.dim }}>{t('friend_requests_title')}</div>
          <div className="flex flex-col gap-2">
            {incoming.map(rel => {
              const p = profilesById[rel.requester_id];
              if (!p) return null;
              return (
                <div key={rel.id} className="flex items-center gap-3">
                  <Avatar name={p.username} photo={p.avatar_url} size={40} />
                  <div className="tt-body text-sm font-semibold flex-1 min-w-0 truncate" style={{ color: C.text }}>{p.username}</div>
                  <button onClick={() => respondRequest(rel, true)} className="p-2 rounded-lg flex-shrink-0" style={{ background: C.greenLight }}>
                    <Check size={16} color="#04140D" />
                  </button>
                  <button onClick={() => respondRequest(rel, false)} className="p-2 rounded-lg flex-shrink-0" style={{ background: C.panel2 }}>
                    <X size={16} color={C.dim} />
                  </button>
                </div>
              );
            })}
          </div>
        </Panel>
      )}

      <div className="tt-body text-sm font-semibold mb-2 px-1" style={{ color: C.dim }}>{t('nav_friends')}</div>
      {!loading && accepted.length === 0 ? (
        <Panel><div className="tt-body text-sm text-center" style={{ color: C.dim }}>{t('friends_none_yet')}</div></Panel>
      ) : (
        <div className="flex flex-col gap-2">
          {accepted.map(rel => {
            const otherId = rel.requester_id === myId ? rel.addressee_id : rel.requester_id;
            const p = profilesById[otherId];
            if (!p) return null;
            return (
              <div key={rel.id} className="rounded-xl p-2.5 flex items-center gap-3" style={{ background: C.panel, border: `1px solid ${C.line}` }}>
                <button onClick={() => onSelectPlayer(p.username, p.id)} className="flex items-center gap-3 flex-1 min-w-0 text-left">
                  <Avatar name={p.username} photo={p.avatar_url} size={40} />
                  <div className="min-w-0">
                    <div className="tt-body text-sm font-semibold truncate" style={{ color: C.text }}>{p.username}</div>
                    {(p.city || p.country) && (
                      <div className="tt-body text-xs truncate" style={{ color: C.dim }}>{[p.city, p.country ? `${countryFlagByName(p.country)} ${p.country}` : null].filter(Boolean).join(', ')}</div>
                    )}
                  </div>
                </button>
                <button onClick={() => removeFriend(rel)} className="p-2 rounded-lg flex-shrink-0" style={{ background: C.panel2 }} title={t('btn_remove_friend')}>
                  <Star size={16} color={C.amber} fill={C.amber} />
                </button>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
}

/* ============================= MY PROFILE ============================= */
function MyProfile({ setView, matchLog, session, profile, setProfile }) {
  const { t, lang } = useT();
  const fileRef = useRef(null);
  const userId = session.user.id;
  const [usernameInput, setUsernameInput] = useState(profile ? profile.username || '' : '');
  const [cityInput, setCityInput] = useState(profile ? profile.city || '' : '');
  const [countryInput, setCountryInput] = useState(profile ? profile.country || '' : '');
  const [confirmingAccount, setConfirmingAccount] = useState(false);
  const [saveError, setSaveError] = useState('');
  const [showAvatarPicker, setShowAvatarPicker] = useState(false);
  const [isEditing, setIsEditing] = useState(false);
  const [deletingAccount, setDeletingAccount] = useState(false);

  useEffect(() => {
    setUsernameInput(profile ? profile.username || '' : '');
    setCityInput(profile ? profile.city || '' : '');
    setCountryInput(profile ? profile.country || '' : '');
  }, [profile]);

  useEffect(() => {
    if (!confirmingAccount) return;
    const timer = setTimeout(() => setConfirmingAccount(false), 5000);
    return () => clearTimeout(timer);
  }, [confirmingAccount]);

  function handleLogout() {
    try {
      Object.keys(window.localStorage).forEach(k => {
        if (k.includes('code-verifier') || k.includes('code_verifier')) {
          window.localStorage.removeItem(k);
        }
      });
    } catch (e) { /* ignore */ }
    supabase.auth.signOut();
  }

  async function handleDeleteAccountClick() {
    if (!confirmingAccount) { setConfirmingAccount(true); return; }
    setConfirmingAccount(false);
    setDeletingAccount(true);
    try {
      await supabase.from('profiles').delete().eq('id', userId);
    } catch (e) { /* best effort */ }
    setProfile(null);
    await supabase.auth.signOut();
  }

  async function saveField(fields) {
    setProfile(p => ({ ...(p || {}), ...fields }));
    setSaveError('');
    try {
      const { error } = await supabase.from('profiles').update(fields).eq('id', userId);
      if (error) setSaveError(error.message);
    } catch (e) {
      setSaveError(e && e.message ? e.message : 'Save failed');
    }
  }

  async function handleFile(e) {
    const file = e.target.files && e.target.files[0];
    if (!file) return;
    try {
      const dataUrl = await resizeImage(file, 240);
      const blob = dataUrlToBlob(dataUrl);
      const path = `${userId}.jpg`;
      const { error: uploadError } = await supabase.storage.from('avatars').upload(path, blob, { upsert: true, contentType: 'image/jpeg' });
      if (uploadError) { setSaveError(uploadError.message); return; }
      const { data } = supabase.storage.from('avatars').getPublicUrl(path);
      await saveField({ avatar_url: `${data.publicUrl}?t=${Date.now()}` });
    } catch (err) { setSaveError(err && err.message ? err.message : 'Upload failed'); }
  }

  const myUsername = profile ? (profile.username || '') : '';
  const stats = aggregateStats(matchLog);
  const me = myUsername ? stats.find(s => s.name.toLowerCase() === myUsername.trim().toLowerCase()) : null;
  const winPct = me && me.played > 0 ? Math.round((me.w / me.played) * 100) : 0;
  const serve = myUsername ? aggregateServeStats(matchLog, me ? me.name : myUsername) : { servePts: 0, returnPts: 0 };
  const hasServeData = serve.servePts + serve.returnPts > 0;
  const streaks = myUsername ? computeStreaks(matchLog, me ? me.name : myUsername) : { current: 0, best: 0, losing: 0 };
  const myBadges = myUsername && myUsername.trim() ? computeBadges(matchLog, me ? me.name : myUsername.trim(), t) : [];
  const myTitle = getPlayerTitle(myBadges.filter(b => b.earned).length, TOTAL_POSSIBLE_BADGES, myUsername, lang, streaks.losing);
  function pct(won, total) { return total > 0 ? Math.round((won / total) * 100) : 0; }

  return (
    <div>
      <BackBar title={t('nav_profile')} onBack={() => setView('home')} />
      {saveError && (
        <Panel style={{ borderColor: C.red, marginBottom: 16 }}>
          <div className="tt-body text-xs" style={{ color: C.red }}>{saveError}</div>
        </Panel>
      )}

      <Panel style={{ marginBottom: 16 }}>
        {!isEditing ? (
          <>
            <div className="flex items-center gap-4 mb-4">
              <Avatar name={myUsername || '?'} photo={profile ? profile.avatar_url : null} size={72} />
              <div className="flex-1 min-w-0">
                <div className="tt-display text-2xl truncate" style={{ color: C.text }}>{myUsername || t('profile_username_placeholder')}</div>
                {myTitle && <div className="tt-body text-xs font-semibold" style={{ color: C.amber }}>{myTitle}</div>}
                {(profile && (profile.city || profile.country)) && (
                  <div className="tt-body text-sm truncate" style={{ color: C.dim }}>
                    {[profile.city, profile.country ? `${countryFlagByName(profile.country)} ${profile.country}` : null].filter(Boolean).join(', ')}
                  </div>
                )}
              </div>
            </div>
            <PrimaryButton onClick={() => setIsEditing(true)} style={{ width: '100%' }}>
              {t('profile_edit_button')}
            </PrimaryButton>
          </>
        ) : (
          <>
            <div className="flex items-center gap-4 mb-4">
              <Avatar name={myUsername || '?'} photo={profile ? profile.avatar_url : null} size={72} />
              <div className="flex-1 min-w-0">
                <div className="tt-body text-xs font-semibold mb-1" style={{ color: C.dim }}>{t('profile_username_label')}</div>
                <input
                  value={usernameInput}
                  onChange={e => setUsernameInput(e.target.value)}
                  onBlur={() => saveField({ username: usernameInput.trim() })}
                  placeholder={t('profile_username_placeholder')}
                  className="tt-body w-full px-3 py-2 rounded-lg outline-none"
                  style={{ background: C.panel2, border: `1px solid ${C.line}`, color: C.text }}
                />
              </div>
            </div>
            <div className="grid grid-cols-2 gap-2 mb-4">
              <div>
                <div className="tt-body text-xs font-semibold mb-1" style={{ color: C.dim }}>{t('profile_city_label')}</div>
                <input
                  value={cityInput}
                  onChange={e => setCityInput(e.target.value)}
                  onBlur={() => saveField({ city: cityInput.trim() })}
                  placeholder={t('profile_city_placeholder')}
                  className="tt-body w-full px-3 py-2 rounded-lg outline-none"
                  style={{ background: C.panel2, border: `1px solid ${C.line}`, color: C.text }}
                />
              </div>
              <div>
                <div className="tt-body text-xs font-semibold mb-1" style={{ color: C.dim }}>{t('profile_country_label')}</div>
                <select
                  value={countryInput}
                  onChange={e => { setCountryInput(e.target.value); saveField({ country: e.target.value }); }}
                  className="tt-body w-full px-3 py-2 rounded-lg outline-none"
                  style={{ background: C.panel2, border: `1px solid ${C.line}`, color: countryInput ? C.text : C.dim }}
                >
                  <option value="" style={{ color: C.dim }}>{t('profile_country_placeholder')}</option>
                  {COUNTRY_CODES.map(([iso, name]) => (
                    <option key={iso} value={name} style={{ color: C.text, background: C.panel2 }}>
                      {flagEmoji(iso)} {name}
                    </option>
                  ))}
                </select>
              </div>
            </div>
            <input ref={fileRef} type="file" accept="image/*" style={{ display: 'none' }} onChange={handleFile} />
            <GhostButton onClick={() => fileRef.current && fileRef.current.click()} style={{ width: '100%', textAlign: 'center' }}>
              <span className="flex items-center justify-center gap-2"><Camera size={15} /> {profile && profile.avatar_url ? t('player_photo_change') : t('player_photo_upload')}</span>
            </GhostButton>
            <GhostButton onClick={() => setShowAvatarPicker(s => !s)} style={{ width: '100%', textAlign: 'center', marginTop: 8 }}>
              <span className="flex items-center justify-center gap-2">
                <User size={15} /> {t('profile_avatar_presets_label')}
                <ChevronDown size={14} style={{ transform: showAvatarPicker ? 'rotate(180deg)' : 'none', transition: 'transform 0.2s' }} />
              </span>
            </GhostButton>
            {showAvatarPicker && (
              <div className="grid grid-cols-6 gap-2 mt-3">
                {AVATAR_CHARACTERS.map(({ emoji, color }) => {
                  const value = `preset:${color}:${emoji}`;
                  const selected = profile && profile.avatar_url === value;
                  return (
                    <button
                      key={emoji}
                      onClick={() => { saveField({ avatar_url: value }); setShowAvatarPicker(false); }}
                      className="rounded-full flex items-center justify-center flex-shrink-0"
                      style={{
                        width: 44, height: 44, background: color,
                        border: selected ? `2px solid ${C.text}` : '2px solid transparent',
                      }}
                    >
                      <span style={{ fontSize: 22, lineHeight: 1 }}>{emoji}</span>
                    </button>
                  );
                })}
              </div>
            )}
            <PrimaryButton onClick={() => { setShowAvatarPicker(false); setIsEditing(false); }} style={{ width: '100%', marginTop: 12 }}>
              {t('profile_save_button')}
            </PrimaryButton>
          </>
        )}
      </Panel>

      {me ? (
        <>
          <Panel style={{ marginBottom: 16 }}>
            <div className="tt-body text-xs mb-3" style={{ color: C.dim }}>{t('player_stats_line', { played: me.played, pct: winPct })}</div>
            <div className="grid grid-cols-2 gap-3">
              <div className="text-center">
                <div className="tt-display text-3xl" style={{ color: C.greenLight }}>{me.w}</div>
                <div className="tt-body text-xs" style={{ color: C.dim }}>{t('player_won')}</div>
              </div>
              <div className="text-center">
                <div className="tt-display text-3xl" style={{ color: C.red }}>{me.l}</div>
                <div className="tt-body text-xs" style={{ color: C.dim }}>{t('player_lost')}</div>
              </div>
              <div className="text-center">
                <div className="tt-display text-xl" style={{ color: C.text }}>{me.setsFor}-{me.setsAgainst}</div>
                <div className="tt-body text-xs" style={{ color: C.dim }}>{t('player_sets_label')}</div>
              </div>
              <div className="text-center">
                <div className="tt-display text-xl" style={{ color: C.text }}>{me.pointsFor}-{me.pointsAgainst}</div>
                <div className="tt-body text-xs" style={{ color: C.dim }}>{t('player_points_label')}</div>
              </div>
              <div className="text-center">
                <div className="tt-display text-xl flex items-center justify-center gap-1" style={{ color: C.amber }}>
                  {streaks.current > 0 && <Flame size={16} color={C.amber} fill={C.amber} />}{streaks.current}
                </div>
                <div className="tt-body text-xs" style={{ color: C.dim }}>{t('streak_current')}</div>
              </div>
              <div className="text-center">
                <div className="tt-display text-xl" style={{ color: C.text }}>{streaks.best}</div>
                <div className="tt-body text-xs" style={{ color: C.dim }}>{t('streak_best')}</div>
              </div>
              <div className="text-center col-span-2">
                <div className="tt-display text-xl" style={{ color: C.greenLight }}>{me.pointsFor}</div>
                <div className="tt-body text-xs" style={{ color: C.dim }}>{t('player_career_points_label')}</div>
              </div>
            </div>
          </Panel>

          {hasServeData && (
            <Panel style={{ marginBottom: 16 }}>
              <div className="tt-body text-sm font-semibold mb-3" style={{ color: C.dim }}>{t('serve_stats_title')}</div>
              <div className="grid grid-cols-2 gap-3 text-center">
                <div>
                  <div className="tt-display text-2xl" style={{ color: C.amber }}>{pct(serve.serveWon, serve.servePts)}%</div>
                  <div className="tt-body text-xs" style={{ color: C.dim }}>{t('own_serve_label')} ({serve.serveWon}/{serve.servePts})</div>
                </div>
                <div>
                  <div className="tt-display text-2xl" style={{ color: C.greenLight }}>{pct(serve.returnWon, serve.returnPts)}%</div>
                  <div className="tt-body text-xs" style={{ color: C.dim }}>{t('return_label')} ({serve.returnWon}/{serve.returnPts})</div>
                </div>
              </div>
            </Panel>
          )}
        </>
      ) : (
        <Panel style={{ marginBottom: 16 }}>
          <div className="tt-body text-sm text-center" style={{ color: C.dim }}>
            {t('profile_no_stats', { name: myUsername || t('profile_username_placeholder') })}
          </div>
        </Panel>
      )}

      <Panel>
        <div className="tt-body text-sm font-semibold mb-3 flex items-center gap-2" style={{ color: C.dim }}>
          <Award size={16} color={C.dim} /> {t('profile_badges_title')}
        </div>
        {myUsername && myUsername.trim() ? (
          <BadgesGrid badges={myBadges} />
        ) : (
          <div className="rounded-xl p-4 text-center" style={{ background: C.panel2, border: `1px dashed ${C.line}` }}>
            <Award size={26} color={C.dim} className="mx-auto mb-2" />
            <div className="tt-body text-xs" style={{ color: C.dim }}>{t('profile_badges_empty')}</div>
          </div>
        )}
      </Panel>

      <Panel style={{ marginTop: 16 }}>
        <button
          onClick={handleLogout}
          className="tt-body w-full px-4 py-2.5 rounded-xl font-semibold"
          style={{ background: 'transparent', color: C.text, border: `1px solid ${C.line}` }}
        >
          {t('settings_logout')}
        </button>
      </Panel>

      <Panel style={{ borderColor: C.red, marginTop: 8 }}>
        <div className="tt-body text-sm font-semibold mb-1" style={{ color: C.red }}>{t('settings_delete_account_label')}</div>
        <div className="tt-body text-xs mb-3" style={{ color: C.dim }}>{t('settings_delete_account_desc')}</div>
        <button
          onClick={handleDeleteAccountClick}
          disabled={deletingAccount}
          className="tt-body w-full px-4 py-2.5 rounded-xl font-semibold transition-colors disabled:opacity-50"
          style={{
            background: confirmingAccount ? C.red : 'transparent',
            color: confirmingAccount ? '#fff' : C.red,
            border: `1px solid ${C.red}`,
          }}
        >
          {confirmingAccount ? t('settings_delete_account_confirm') : t('settings_delete_account_label')}
        </button>
      </Panel>
    </div>
  );
}

/* ============================= FREE PLAY ============================= */
function FreePlaySetup({ setView, state, setState, session, settings }) {
  const { t } = useT();
  const { mode, bestOf } = state;
  const [participants, setParticipants] = useState(() => (state.presetParticipants ? state.presetParticipants : [null, null]));

  useEffect(() => {
    if (state.presetParticipants) {
      setState(s => { const { presetParticipants, ...rest } = s; return rest; });
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);
  const [teamParticipants, setTeamParticipants] = useState([[null, null], [null, null]]);
  const [friendsList, setFriendsList] = useState([]);
  const myProfileId = session && session.user ? session.user.id : null;

  useEffect(() => {
    if (!myProfileId) return;
    (async () => {
      try {
        const { data: rels } = await supabase
          .from('friendships')
          .select('*')
          .eq('status', 'accepted')
          .or(`requester_id.eq.${myProfileId},addressee_id.eq.${myProfileId}`);
        const otherIds = (rels || []).map(r => (r.requester_id === myProfileId ? r.addressee_id : r.requester_id));
        if (otherIds.length) {
          const { data: profs } = await supabase.from('profiles').select('id, username, avatar_url').in('id', otherIds);
          setFriendsList(profs || []);
        }
      } catch (e) { /* best effort */ }
    })();
  }, [myProfileId]);

  function setTeamSlot(teamIdx, slotIdx, p) {
    setTeamParticipants(prev => {
      const next = prev.map(team => team.slice());
      next[teamIdx][slotIdx] = p;
      return next;
    });
  }

  const setMode = m => setState(s => ({ ...s, mode: m }));
  const setBestOf = b => setState(s => ({ ...s, bestOf: b }));

  function start() {
    if (mode === 'enkel') {
      const finalNames = [
        (participants[0] && participants[0].name.trim()) || t('placeholder_player', { n: 1 }),
        (participants[1] && participants[1].name.trim()) || t('placeholder_player', { n: 2 }),
      ];
      const participantIds = {
        teamA: [participants[0] ? participants[0].profileId : null],
        teamB: [participants[1] ? participants[1].profileId : null],
      };
      setState(s => ({ ...s, names: finalNames, pairMap: null, participantIds }));
    } else {
      const teamInfo = teamParticipants.map((team, i) => {
        const p1 = (team[0] && team[0].name.trim()) || t('placeholder_player', { n: i * 2 + 1 });
        const p2 = (team[1] && team[1].name.trim()) || t('placeholder_player', { n: i * 2 + 2 });
        return { display: `${p1} & ${p2}`, p1, p2 };
      });
      const finalNames = teamInfo.map(ti => ti.display);
      const pairMap = {};
      teamInfo.forEach(ti => { pairMap[ti.display] = [ti.p1, ti.p2]; });
      const participantIds = {
        teamA: teamParticipants[0].map(p => (p ? p.profileId : null)),
        teamB: teamParticipants[1].map(p => (p ? p.profileId : null)),
      };
      setState(s => ({ ...s, names: finalNames, pairMap, participantIds }));
    }
    setView('freeplay-play');
  }

  return (
    <div>
      <BackBar title={t('freeplay_title')} onBack={() => setView('home')} />
      <div className="flex flex-col gap-4">
        <Panel>
          <div className="tt-body text-sm mb-2 font-semibold" style={{ color: C.dim }}>{t('mode_label')}</div>
          <SegButton options={[{ value: 'enkel', label: t('mode_singles') }, { value: 'dubbel', label: t('mode_doubles') }]} value={mode} onChange={setMode} />
        </Panel>
        <Panel>
          <div className="tt-body text-sm mb-2 font-semibold" style={{ color: C.dim }}>{t('sets_count_label')}</div>
          {settings && settings.customSets ? (
            <div className="flex items-center gap-2">
              <input
                type="number"
                min="1"
                max="99"
                value={bestOf}
                onChange={e => {
                  const v = parseInt(e.target.value, 10);
                  setBestOf(Number.isNaN(v) ? 1 : Math.max(1, Math.min(99, v)));
                }}
                className="tt-body w-24 px-3 py-2 rounded-lg outline-none text-center"
                style={{ background: C.panel2, border: `1px solid ${C.line}`, color: C.text }}
              />
              <span className="tt-body text-sm" style={{ color: C.dim }}>{t('custom_sets_label')}</span>
            </div>
          ) : (
            <BestOfPicker options={[3, 5, 7]} value={bestOf} onChange={setBestOf} />
          )}
        </Panel>
        <Panel>
          <div className="tt-body text-sm mb-2 font-semibold" style={{ color: C.dim }}>{mode === 'dubbel' ? t('teams_label') : t('players_label')}</div>
          <div className="tt-body text-xs mb-3" style={{ color: C.dim }}>{t('picker_hint')}</div>
          {mode === 'enkel' ? (
            <div className="flex flex-col gap-3">
              <PlayerPicker value={participants[0]} onChange={p => setParticipants(prev => [p, prev[1]])} placeholder={t('placeholder_player', { n: 1 })} friendsList={friendsList} myProfileId={myProfileId} />
              <PlayerPicker value={participants[1]} onChange={p => setParticipants(prev => [prev[0], p])} placeholder={t('placeholder_player', { n: 2 })} friendsList={friendsList} myProfileId={myProfileId} />
            </div>
          ) : (
            <div className="flex flex-col gap-4">
              {[0, 1].map(teamIdx => (
                <div key={teamIdx} className="flex flex-col gap-2">
                  <div className="tt-body text-xs font-semibold" style={{ color: C.dim }}>{t('team_label', { n: teamIdx + 1 })}</div>
                  <PlayerPicker
                    value={teamParticipants[teamIdx][0]}
                    onChange={p => setTeamSlot(teamIdx, 0, p)}
                    placeholder={t('placeholder_player', { n: teamIdx * 2 + 1 })}
                    friendsList={friendsList}
                    myProfileId={myProfileId}
                  />
                  <PlayerPicker
                    value={teamParticipants[teamIdx][1]}
                    onChange={p => setTeamSlot(teamIdx, 1, p)}
                    placeholder={t('placeholder_player', { n: teamIdx * 2 + 2 })}
                    friendsList={friendsList}
                    myProfileId={myProfileId}
                  />
                </div>
              ))}
            </div>
          )}
        </Panel>
        <PrimaryButton onClick={start}>{t('start_match')}</PrimaryButton>
      </div>
    </div>
  );
}

function FreePlayPlay({ setView, state, settings, recordMatch, session }) {
  const { t, lang } = useT();
  const { bestOf, names, mode, pairMap, participantIds } = state;
  const [result, setResult] = useState(null);
  const [showShare, setShowShare] = useState(false);

  function handleComplete(r) {
    const nameA = names[0], nameB = names[1];
    const [totalPointsA, totalPointsB] = sumPoints(r.score.sets);
    recordMatch({
      id: `${Date.now()}-${Math.random().toString(36).slice(2, 7)}`,
      timestamp: Date.now(),
      kind: 'freeplay',
      mode,
      nameA, nameB,
      setsA: r.score.setsA, setsB: r.score.setsB,
      totalPointsA, totalPointsB,
      winner: r.winner === 'a' ? nameA : nameB,
      ...prepareReportData({ setsA: r.score.setsA, setsB: r.score.setsB, sets: r.score.sets, bestOf, durationMs: r.durationMs }),
      pointLog: r.score.pointLog || [],
    });
    const teamAIds = participantIds ? participantIds.teamA : [];
    const teamBIds = participantIds ? participantIds.teamB : [];
    const bothTeamsLinked = teamAIds.length > 0 && teamBIds.length > 0 && teamAIds.every(Boolean) && teamBIds.every(Boolean);
    if (bothTeamsLinked && session && session.user) {
      (async () => {
        try {
          await supabase.from('matches').insert({
            kind: 'freeplay',
            mode,
            team_a_ids: teamAIds,
            team_b_ids: teamBIds,
            sets_a: r.score.setsA,
            sets_b: r.score.setsB,
            total_points_a: totalPointsA,
            total_points_b: totalPointsB,
            winner_team: r.winner,
            best_of: bestOf,
            sets_detail: r.score.sets,
            point_log: r.score.pointLog || [],
            duration_ms: r.durationMs,
            created_by: session.user.id,
          });
        } catch (e) { /* best effort — online sync is additive, local record above already saved */ }
      })();
    }
    setResult(r);
  }

  if (result) {
    const winnerName = result.winner === 'a' ? names[0] : names[1];
    return (
      <div>
        <BackBar title={t('result_title')} onBack={() => setView('home')} />
        <Panel style={{ textAlign: 'center' }}>
          <Trophy size={36} color={C.amber} className="mx-auto mb-3" />
          <div className="tt-display text-3xl mb-1" style={{ color: C.text }}>{t('result_win', { name: winnerName })}</div>
          <div className="tt-body text-sm mb-5" style={{ color: C.dim }}>{t('result_sets', { a: result.score.setsA, b: result.score.setsB })}</div>
          <div className="flex gap-2 justify-center flex-wrap">
            <PrimaryButton onClick={() => setShowShare(true)}>
              <span className="flex items-center gap-2"><Share2 size={15} /> {t('btn_share')}</span>
            </PrimaryButton>
            <GhostButton onClick={() => setResult(null)}>{t('btn_replay')}</GhostButton>
            <GhostButton onClick={() => setView('freeplay-setup')}>{t('btn_new_settings')}</GhostButton>
            <GhostButton onClick={() => setView('home')}>{t('btn_home_menu')}</GhostButton>
          </div>
        </Panel>
        {showShare && (
          <ShareModal
            shareText={buildShareText({ nameA: names[0], nameB: names[1], setsA: result.score.setsA, setsB: result.score.setsB, winner: winnerName, subtitle: t('freeplay_title'), t })}
            drawCard={() => drawResultCard({ nameA: names[0], nameB: names[1], setsA: result.score.setsA, setsB: result.score.setsB, winner: winnerName, subtitle: t('freeplay_title'), headerText: t('card_header') })}
            onClose={() => setShowShare(false)}
          />
        )}
      </div>
    );
  }

  return (
    <MatchScoreboard
      nameA={names[0]}
      nameB={names[1]}
      bestOf={bestOf}
      settings={settings}
      mode={mode}
      pairA={pairMap ? pairMap[names[0]] : null}
      pairB={pairMap ? pairMap[names[1]] : null}
      onCancel={() => setView('freeplay-setup')}
      onComplete={handleComplete}
    />
  );
}

/* ============================= COMPETITION ============================= */
function CompetitionSetup({ setView, onStart, session }) {
  const { t } = useT();
  const [mode, setModeRaw] = useState('enkel');
  const [cadence, setCadence] = useState('weekly');
  const [bestOf, setBestOf] = useState(5);
  const [count, setCount] = useState(4);
  const [participants, setParticipants] = useState([null, null, null, null]);
  const myProfileId = session && session.user ? session.user.id : null;
  const friendsList = useFriendsList(myProfileId);

  function setMode(m) {
    setModeRaw(m);
    setParticipants(prev => prev.map(() => m === 'dubbel' ? [null, null] : null));
  }

  function start() {
    const finalNames = participants.map((slot, i) => {
      if (mode === 'dubbel') {
        const p1 = (slot && slot[0] && slot[0].name.trim()) || t('placeholder_player', { n: i * 2 + 1 });
        const p2 = (slot && slot[1] && slot[1].name.trim()) || t('placeholder_player', { n: i * 2 + 2 });
        return `${p1} & ${p2}`;
      }
      return (slot && slot.name.trim()) || t('placeholder_player', { n: i + 1 });
    });
    let pairMap = null;
    if (mode === 'dubbel') {
      pairMap = {};
      participants.forEach((slot, i) => {
        const p1 = (slot && slot[0] && slot[0].name.trim()) || t('placeholder_player', { n: i * 2 + 1 });
        const p2 = (slot && slot[1] && slot[1].name.trim()) || t('placeholder_player', { n: i * 2 + 2 });
        pairMap[`${p1} & ${p2}`] = [p1, p2];
      });
    }
    const participantIdsList = participants.map(slot => {
      if (mode === 'dubbel') return (slot || [null, null]).map(p => (p ? p.profileId : null));
      return [slot ? slot.profileId : null];
    });
    onStart({
      cadence, mode, bestOf,
      names: finalNames,
      pairMap,
      participantIdsList,
      periodNumber: 1,
      matches: generateRoundRobin(finalNames),
      history: [],
    });
  }

  return (
    <div>
      <BackBar title={t('competition_title')} onBack={() => setView('home')} />
      <div className="flex flex-col gap-4">
        <Panel>
          <div className="tt-body text-sm mb-2 font-semibold" style={{ color: C.dim }}>{t('cadence_label')}</div>
          <SegButton options={[{ value: 'weekly', label: t('cadence_weekly') }, { value: 'monthly', label: t('cadence_monthly') }]} value={cadence} onChange={setCadence} />
        </Panel>
        <Panel>
          <div className="tt-body text-sm mb-2 font-semibold" style={{ color: C.dim }}>{t('mode_label')}</div>
          <SegButton options={[{ value: 'enkel', label: t('mode_singles') }, { value: 'dubbel', label: t('mode_doubles') }]} value={mode} onChange={setMode} />
        </Panel>
        <Panel>
          <div className="tt-body text-sm mb-2 font-semibold" style={{ color: C.dim }}>{t('sets_count_label')}</div>
          <BestOfPicker options={[5, 7]} value={bestOf} onChange={setBestOf} />
          <div className="tt-body text-xs mt-2" style={{ color: C.dim }}>{t('competition_sets_note')}</div>
        </Panel>
        <Panel>
          <div className="tt-body text-sm mb-2 font-semibold" style={{ color: C.dim }}>{t('competition_participants_label')}</div>
          <ParticipantCountStepper count={count} setCount={setCount} participants={participants} setParticipants={setParticipants} suffix={t('count_suffix')} mode={mode} />
        </Panel>
        <Panel>
          <div className="tt-body text-sm mb-2 font-semibold" style={{ color: C.dim }}>{mode === 'dubbel' ? t('teams_label') : t('players_label')}</div>
          <ParticipantList participants={participants} setParticipants={setParticipants} mode={mode} friendsList={friendsList} myProfileId={myProfileId} t={t} />
        </Panel>
        <PrimaryButton onClick={start}>{t('start_competition', { n: (count * (count - 1)) / 2 })}</PrimaryButton>
      </div>
    </div>
  );
}

function CompetitionPlay({ setView, competition, setCompetition, settings, recordMatch, session }) {
  const { t, lang } = useT();
  const { names, matches, bestOf, cadence, periodNumber, history, mode, pairMap, participantIdsList } = competition;
  const [active, setActive] = useState(null);
  const [showChampionShare, setShowChampionShare] = useState(false);
  const [detailMatch, setDetailMatch] = useState(null);
  const curPeriodLabel = periodLabel(cadence, periodNumber, t);

  function completeMatch(result) {
    const m = matches[active];
    const winnerName = result.winner === 'a' ? m.p1 : m.p2;
    const [totalPointsA, totalPointsB] = sumPoints(result.score.sets);
    recordMatch({
      id: `${Date.now()}-${Math.random().toString(36).slice(2, 7)}`,
      timestamp: Date.now(),
      kind: 'competition',
      cadence, periodNumber,
      nameA: m.p1, nameB: m.p2,
      setsA: result.score.setsA, setsB: result.score.setsB,
      totalPointsA, totalPointsB,
      winner: winnerName,
      ...prepareReportData({ setsA: result.score.setsA, setsB: result.score.setsB, sets: result.score.sets, bestOf, durationMs: result.durationMs }),
      pointLog: result.score.pointLog || [],
    });
    if (participantIdsList && session && session.user) {
      const idxA = names.indexOf(m.p1);
      const idxB = names.indexOf(m.p2);
      const teamAIds = idxA >= 0 ? participantIdsList[idxA] : [];
      const teamBIds = idxB >= 0 ? participantIdsList[idxB] : [];
      const bothLinked = teamAIds.length > 0 && teamBIds.length > 0 && teamAIds.every(Boolean) && teamBIds.every(Boolean);
      if (bothLinked) {
        (async () => {
          try {
            await supabase.from('matches').insert({
              kind: 'competition',
              mode,
              cadence, period_number: periodNumber,
              team_a_ids: teamAIds,
              team_b_ids: teamBIds,
              sets_a: result.score.setsA,
              sets_b: result.score.setsB,
              total_points_a: totalPointsA,
              total_points_b: totalPointsB,
              winner_team: result.winner,
              best_of: bestOf,
              sets_detail: result.score.sets,
              point_log: result.score.pointLog || [],
              duration_ms: result.durationMs,
              created_by: session.user.id,
            });
          } catch (e) { /* best effort — online sync is additive, local record above already saved */ }
        })();
      }
    }
    setCompetition(s => {
      const newMatches = s.matches.map((mm, i) => i === active ? { ...mm, winner: winnerName, score: result.score } : mm);
      return { ...s, matches: newMatches };
    });
    setActive(null);
  }

  function startNextPeriod() {
    setCompetition(s => ({
      ...s,
      periodNumber: s.periodNumber + 1,
      matches: generateRoundRobin(s.names),
      history: [...s.history, { periodNumber: s.periodNumber, matches: s.matches }],
    }));
  }

  function newCompetition() {
    setCompetition(null);
    setView('competition-setup');
  }

  const allMatches = [...history.flatMap(h => h.matches), ...matches];
  const standings = computeStandings(names, allMatches);
  const played = matches.filter(m => m.winner).length;
  const periodDone = played === matches.length && matches.length > 0;
  const champion = periodDone ? standings[0].name : null;
  const celebrating = useCelebration(champion);

  return (
    <div>
      <BackBar
        title={`${t('competition_title')} \u2013 ${curPeriodLabel}`}
        onBack={() => setView('home')}
        right={<GhostButton onClick={newCompetition} style={{ fontSize: 11, padding: '6px 10px' }}>{t('btn_new_competition')}</GhostButton>}
      />

      {celebrating && <Confetti />}
      {champion && (
        <Panel style={{ textAlign: 'center', marginBottom: 16, background: C.green }} >
          <div className="trophy-pop">
            <Trophy size={30} color="#fff" className="mx-auto mb-2" />
            <div className="tt-display text-3xl" style={{ color: '#fff' }}>{t('competition_champion', { name: champion })}</div>
            <div className="tt-body text-xs mt-1" style={{ color: 'rgba(255,255,255,0.8)' }}>{t('period_done_note', { period: curPeriodLabel })}</div>
            <div className="flex gap-2 justify-center flex-wrap mt-3">
              <PrimaryButton onClick={startNextPeriod}>{t('btn_next_period', { period: periodLabel(cadence, periodNumber + 1, t) })}</PrimaryButton>
              <GhostButton onClick={() => setShowChampionShare(true)} style={{ borderColor: 'rgba(255,255,255,0.4)', color: '#fff' }}>
                <span className="flex items-center gap-2"><Share2 size={14} /> {t('btn_share_small')}</span>
              </GhostButton>
            </div>
          </div>
        </Panel>
      )}
      {showChampionShare && (
        <ShareModal
          shareText={buildChampionShareText({ champion, subtitle: curPeriodLabel, t })}
          drawCard={() => drawChampionCard({ champion, subtitle: curPeriodLabel, headerText: t('card_header'), champLabel: t('card_champion_label') })}
          onClose={() => setShowChampionShare(false)}
        />
      )}

      <Panel style={{ marginBottom: 16 }}>
        <div className="tt-body text-sm font-semibold mb-3" style={{ color: C.dim }}>{t('season_standing')}</div>
        <div className="flex flex-col gap-1.5">
          {standings.map((row, i) => (
            <div key={row.name} className="grid items-center px-2 py-1.5 rounded-lg tt-body text-sm" style={{ gridTemplateColumns: '1fr 40px 40px 60px', background: i === 0 ? C.panel2 : 'transparent', color: C.text }}>
              <span className="truncate">{i + 1}. {row.name}</span>
              <span className="text-center">{row.w}</span>
              <span className="text-center">{row.l}</span>
              <span className="text-center" style={{ color: C.dim }}>{row.setsFor}-{row.setsAgainst}</span>
            </div>
          ))}
        </div>
      </Panel>

      <div className="tt-body text-sm font-semibold mb-2" style={{ color: C.dim }}>{t('competition_standing', { played, total: matches.length })}</div>
      <div className="flex flex-col gap-2">
        {matches.map((m, i) => (
          <button
            key={m.id}
            onClick={() => m.winner ? setDetailMatch(m) : setActive(i)}
            className="rounded-xl p-3 flex justify-between items-center"
            style={{ background: C.panel, border: `1px solid ${C.line}` }}
          >
            <span className="tt-body text-sm" style={{ color: C.text }}>{m.p1} <span style={{ color: C.dim }}>vs</span> {m.p2}</span>
            {m.winner ? (
              <span className="tt-body text-xs px-2 py-1 rounded-md flex items-center gap-1" style={{ background: C.green, color: '#fff' }}>
                <Check size={12} /> {m.score.setsA}-{m.score.setsB}
              </span>
            ) : (
              <span className="tt-body text-xs px-2 py-1 rounded-md" style={{ background: C.panel2, color: C.amber }}>{t('badge_play')}</span>
            )}
          </button>
        ))}
      </div>

      {detailMatch && (
        <MatchDetailModal
          match={{
            nameA: detailMatch.p1, nameB: detailMatch.p2,
            setsA: detailMatch.score.setsA, setsB: detailMatch.score.setsB,
            winner: detailMatch.winner,
            modeLabel: t('label_competition_period', { period: curPeriodLabel }),
            timestamp: Date.now(),
            pointLog: detailMatch.score.pointLog || [],
          }}
          onClose={() => setDetailMatch(null)}
        />
      )}

      {active !== null && (
        <MatchScoreboard
          nameA={matches[active].p1}
          nameB={matches[active].p2}
          bestOf={bestOf}
          settings={settings}
          mode={mode}
          pairA={pairMap ? pairMap[matches[active].p1] : null}
          pairB={pairMap ? pairMap[matches[active].p2] : null}
          onCancel={() => setActive(null)}
          onComplete={completeMatch}
        />
      )}
    </div>
  );
}

/* ============================= TOURNAMENT ============================= */
function TournamentSetup({ setView, state, setState, session }) {
  const { t } = useT();
  const { mode, count } = state;
  const [participants, setParticipants] = useState(() => Array.from({ length: count }, () => (mode === 'dubbel' ? [null, null] : null)));
  const myProfileId = session && session.user ? session.user.id : null;
  const friendsList = useFriendsList(myProfileId);

  function setMode(m) {
    setState(s => ({ ...s, mode: m }));
    setParticipants(prev => prev.map(() => m === 'dubbel' ? [null, null] : null));
  }
  const setCount = c => setState(s => ({ ...s, count: c }));

  function start() {
    const finalNames = participants.map((slot, i) => {
      if (mode === 'dubbel') {
        const p1 = (slot && slot[0] && slot[0].name.trim()) || t('placeholder_player', { n: i * 2 + 1 });
        const p2 = (slot && slot[1] && slot[1].name.trim()) || t('placeholder_player', { n: i * 2 + 2 });
        return `${p1} & ${p2}`;
      }
      return (slot && slot.name.trim()) || t('placeholder_player', { n: i + 1 });
    });
    let pairMap = null;
    if (mode === 'dubbel') {
      pairMap = {};
      participants.forEach((slot, i) => {
        const p1 = (slot && slot[0] && slot[0].name.trim()) || t('placeholder_player', { n: i * 2 + 1 });
        const p2 = (slot && slot[1] && slot[1].name.trim()) || t('placeholder_player', { n: i * 2 + 2 });
        pairMap[`${p1} & ${p2}`] = [p1, p2];
      });
    }
    const participantIdsList = participants.map(slot => {
      if (mode === 'dubbel') return (slot || [null, null]).map(p => (p ? p.profileId : null));
      return [slot ? slot.profileId : null];
    });
    const rounds = generateBracket(finalNames);
    setState(s => ({ ...s, names: finalNames, pairMap, participantIdsList, rounds }));
    setView('tournament-play');
  }

  return (
    <div>
      <BackBar title={t('tournament_title')} onBack={() => setView('home')} />
      <div className="flex flex-col gap-4">
        <Panel>
          <div className="tt-body text-sm mb-2 font-semibold" style={{ color: C.dim }}>{t('mode_label')}</div>
          <SegButton options={[{ value: 'enkel', label: t('mode_singles') }, { value: 'dubbel', label: t('mode_doubles') }]} value={mode} onChange={setMode} />
        </Panel>
        <Panel>
          <div className="tt-body text-sm mb-1 font-semibold" style={{ color: C.dim }}>{t('sets_count_label')}</div>
          <div className="tt-body text-sm" style={{ color: C.text }}>{t('tournament_info1')}</div>
          <div className="tt-body text-sm" style={{ color: C.text }}>{t('tournament_info2')}</div>
        </Panel>
        <Panel>
          <div className="tt-body text-sm mb-2 font-semibold" style={{ color: C.dim }}>{t('tournament_participants_label')}</div>
          <ParticipantCountStepper count={count} setCount={setCount} participants={participants} setParticipants={setParticipants} suffix={t('count_suffix')} mode={mode} />
        </Panel>
        <Panel>
          <div className="tt-body text-sm mb-2 font-semibold" style={{ color: C.dim }}>{mode === 'dubbel' ? t('teams_label') : t('players_label')}</div>
          <ParticipantList participants={participants} setParticipants={setParticipants} mode={mode} friendsList={friendsList} myProfileId={myProfileId} t={t} />
        </Panel>
        <PrimaryButton onClick={start}>
          <span className="flex items-center gap-2"><Shuffle size={16} /> {t('start_tournament')}</span>
        </PrimaryButton>
      </div>
    </div>
  );
}

function TournamentPlay({ setView, state, setState, settings, recordMatch, session }) {
  const { t, lang } = useT();
  const { rounds, mode, pairMap, names, participantIdsList } = state;
  const [active, setActive] = useState(null);
  const [showChampionShare, setShowChampionShare] = useState(false);
  const [detailMatch, setDetailMatch] = useState(null);

  function completeMatch(result) {
    const { roundIdx, matchIdx } = active;
    const round = rounds[roundIdx];
    const match = round.matches[matchIdx];
    const winnerName = result.winner === 'a' ? match.p1 : match.p2;
    const [totalPointsA, totalPointsB] = sumPoints(result.score.sets);
    recordMatch({
      id: `${Date.now()}-${Math.random().toString(36).slice(2, 7)}`,
      timestamp: Date.now(),
      kind: 'tournament',
      roundKey: round.nameKey,
      nameA: match.p1, nameB: match.p2,
      setsA: result.score.setsA, setsB: result.score.setsB,
      totalPointsA, totalPointsB,
      winner: winnerName,
      ...prepareReportData({ setsA: result.score.setsA, setsB: result.score.setsB, sets: result.score.sets, bestOf: round.bestOf, durationMs: result.durationMs }),
      pointLog: result.score.pointLog || [],
    });
    if (participantIdsList && names && session && session.user) {
      const idxA = names.indexOf(match.p1);
      const idxB = names.indexOf(match.p2);
      const teamAIds = idxA >= 0 ? participantIdsList[idxA] : [];
      const teamBIds = idxB >= 0 ? participantIdsList[idxB] : [];
      const bothLinked = teamAIds.length > 0 && teamBIds.length > 0 && teamAIds.every(Boolean) && teamBIds.every(Boolean);
      if (bothLinked) {
        (async () => {
          try {
            await supabase.from('matches').insert({
              kind: 'tournament',
              mode,
              round_key: round.nameKey,
              team_a_ids: teamAIds,
              team_b_ids: teamBIds,
              sets_a: result.score.setsA,
              sets_b: result.score.setsB,
              total_points_a: totalPointsA,
              total_points_b: totalPointsB,
              winner_team: result.winner,
              best_of: round.bestOf,
              sets_detail: result.score.sets,
              point_log: result.score.pointLog || [],
              duration_ms: result.durationMs,
              created_by: session.user.id,
            });
          } catch (e) { /* best effort — online sync is additive, local record above already saved */ }
        })();
      }
    }
    setState(s => ({ ...s, rounds: recordBracketResult(s.rounds, roundIdx, matchIdx, winnerName, result.score) }));
    setActive(null);
  }

  const lastRound = rounds[rounds.length - 1];
  const champion = lastRound && lastRound.matches[0].winner;
  const celebrating = useCelebration(champion);

  return (
    <div>
      <BackBar title={t('tournament_title')} onBack={() => setView('home')} />

      {celebrating && <Confetti />}
      {champion && (
        <Panel style={{ textAlign: 'center', marginBottom: 16, background: C.green }}>
          <div className="trophy-pop">
            <Trophy size={30} color="#fff" className="mx-auto mb-2" />
            <div className="tt-display text-3xl" style={{ color: '#fff' }}>{t('tournament_champion', { name: champion })}</div>
            <GhostButton onClick={() => setShowChampionShare(true)} style={{ marginTop: 12, borderColor: 'rgba(255,255,255,0.4)', color: '#fff' }}>
              <span className="flex items-center gap-2"><Share2 size={14} /> {t('btn_share_small')}</span>
            </GhostButton>
          </div>
        </Panel>
      )}
      {showChampionShare && (
        <ShareModal
          shareText={buildChampionShareText({ champion, subtitle: t('tournament_title'), t })}
          drawCard={() => drawChampionCard({ champion, subtitle: t('tournament_title'), headerText: t('card_header'), champLabel: t('card_champion_label') })}
          onClose={() => setShowChampionShare(false)}
        />
      )}

      <div className="flex gap-4 overflow-x-auto pb-2">
        {rounds.map((round, ri) => (
          <div key={ri} className="flex flex-col gap-3" style={{ minWidth: 220 }}>
            <div className="tt-body text-xs font-bold uppercase tracking-wide text-center" style={{ color: C.amber }}>
              {roundLabel(round.nameKey, t)} <span style={{ color: C.dim }}>&middot; bo{round.bestOf}</span>
            </div>
            {round.matches.map((m, mi) => {
              const ready = m.p1 && m.p2 && !m.winner;
              const finished = m.winner && m.score && m.score !== 'bye';
              return (
                <button
                  key={m.id}
                  disabled={!ready && !finished}
                  onClick={() => {
                    if (ready) setActive({ roundIdx: ri, matchIdx: mi });
                    else if (finished) setDetailMatch({ m, round });
                  }}
                  className="rounded-xl p-3 text-left disabled:opacity-60"
                  style={{ background: C.panel, border: `1px solid ${C.line}` }}
                >
                  {[m.p1, m.p2].map((p, side) => (
                    <div key={side} className="flex justify-between items-center py-1 tt-body text-sm" style={{
                      color: m.winner === p ? C.greenLight : C.text,
                      fontWeight: m.winner === p ? 700 : 400,
                    }}>
                      <span className="truncate">{p || <span style={{ color: C.dim }}>&mdash;</span>}</span>
                      {m.score && m.score !== 'bye' && (
                        <span style={{ color: C.dim }}>{side === 0 ? m.score.setsA : m.score.setsB}</span>
                      )}
                    </div>
                  ))}
                  {!m.winner && m.p1 && m.p2 && <div className="tt-body text-xs mt-1" style={{ color: C.amber }}>{t('tournament_play_match')}</div>}
                  {m.score === 'bye' && <div className="tt-body text-xs mt-1" style={{ color: C.dim }}>{t('tournament_bye')}</div>}
                </button>
              );
            })}
          </div>
        ))}
      </div>

      {detailMatch && (
        <MatchDetailModal
          match={{
            nameA: detailMatch.m.p1, nameB: detailMatch.m.p2,
            setsA: detailMatch.m.score.setsA, setsB: detailMatch.m.score.setsB,
            winner: detailMatch.m.winner,
            modeLabel: t('label_tournament', { round: roundLabel(detailMatch.round.nameKey, t) }),
            timestamp: Date.now(),
            pointLog: detailMatch.m.score.pointLog || [],
          }}
          onClose={() => setDetailMatch(null)}
        />
      )}

      {active && (
        <MatchScoreboard
          nameA={rounds[active.roundIdx].matches[active.matchIdx].p1}
          nameB={rounds[active.roundIdx].matches[active.matchIdx].p2}
          bestOf={rounds[active.roundIdx].bestOf}
          settings={settings}
          mode={mode}
          pairA={pairMap ? pairMap[rounds[active.roundIdx].matches[active.matchIdx].p1] : null}
          pairB={pairMap ? pairMap[rounds[active.roundIdx].matches[active.matchIdx].p2] : null}
          onCancel={() => setActive(null)}
          onComplete={completeMatch}
        />
      )}
    </div>
  );
}

/* ============================= APP ============================= */
export default function App() {
  const [view, setView] = useState('home');
  const [loaded, setLoaded] = useState(false);
  const [settings, setSettings] = useState({ coinToss: false, voice: false, setBreaks: true, pointSound: true, customSets: false });
  const [matchLog, setMatchLog] = useState([]);
  const [photos, setPhotos] = useState({});
  const [selectedPlayer, setSelectedPlayer] = useState(null);
  const [selectedPlayerProfileId, setSelectedPlayerProfileId] = useState(null);
  const [selectedGroupId, setSelectedGroupId] = useState(null);
  const [selectedGroupName, setSelectedGroupName] = useState('');
  const [lang, setLangState] = useState('nl');
  const [competition, setCompetitionState] = useState(null);
  const [friends, setFriendsState] = useState([]);
  const [profile, setProfile] = useState(null);
  const [session, setSession] = useState(undefined); // undefined = still checking, null = logged out, object = logged in
  const loadedProfileIdRef = useRef(null);

  useEffect(() => {
    supabase.auth.getSession().then(({ data }) => setSession(data.session));
    const { data: listener } = supabase.auth.onAuthStateChange((event, newSession) => {
      setSession(newSession);
      if (event === 'SIGNED_IN') setView('myprofile');
    });
    return () => listener.subscription.unsubscribe();
  }, []);

  useEffect(() => {
    const uid = session && session.user ? session.user.id : null;
    if (!uid) { setProfile(null); loadedProfileIdRef.current = null; return; }
    if (loadedProfileIdRef.current === uid) return; // already loaded for this user — don't refetch and clobber unsaved edits
    loadedProfileIdRef.current = uid;
    const user = session.user;
    (async () => {
      try {
        const { data: existing } = await supabase.from('profiles').select('*').eq('id', uid).maybeSingle();
        if (existing) {
          setProfile(existing);
        } else {
          const meta = user.user_metadata || {};
          const suggestedName = meta.full_name || meta.name || (user.email ? user.email.split('@')[0] : 'Speler');
          const { data: created } = await supabase.from('profiles').insert({
            id: uid,
            username: suggestedName,
            avatar_url: meta.avatar_url || meta.picture || null,
          }).select().single();
          setProfile(created || null);
        }
      } catch (e) { /* profile creation best-effort */ }
    })();
  }, [session]);

  const [onlineMatches, setOnlineMatches] = useState([]);

  async function refreshOnlineMatches() {
    const uid = session && session.user ? session.user.id : null;
    if (!uid) { setOnlineMatches([]); return; }
    try {
      const { data: rows } = await supabase
        .from('matches')
        .select('*')
        .or(`team_a_ids.cs.{${uid}},team_b_ids.cs.{${uid}}`)
        .neq('created_by', uid);
      if (!rows || !rows.length) { setOnlineMatches([]); return; }
      const idSet = new Set();
      rows.forEach(m => {
        (m.team_a_ids || []).forEach(id => idSet.add(id));
        (m.team_b_ids || []).forEach(id => idSet.add(id));
      });
      const { data: profs } = await supabase.from('profiles').select('id, username').in('id', Array.from(idSet));
      const nameById = {};
      (profs || []).forEach(p => { nameById[p.id] = p.username; });
      const converted = rows.map(m => {
        const nameA = (m.team_a_ids || []).map(id => nameById[id] || '?').join(' & ');
        const nameB = (m.team_b_ids || []).map(id => nameById[id] || '?').join(' & ');
        const winner = m.winner_team === 'a' ? nameA : nameB;
        const [totalPointsA, totalPointsB] = m.total_points_a != null
          ? [m.total_points_a, m.total_points_b]
          : sumPoints(m.sets_detail || []);
        return {
          id: m.id,
          timestamp: new Date(m.created_at).getTime(),
          kind: m.kind,
          mode: m.mode,
          nameA, nameB,
          setsA: m.sets_a, setsB: m.sets_b,
          totalPointsA, totalPointsB,
          winner,
          cadence: m.cadence,
          periodNumber: m.period_number,
          roundKey: m.round_key,
          pointLog: m.point_log || [],
          ...prepareReportData({ setsA: m.sets_a, setsB: m.sets_b, sets: m.sets_detail || [], bestOf: m.best_of, durationMs: m.duration_ms }),
          onlineOnly: true,
        };
      });
      setOnlineMatches(converted);
    } catch (e) { /* best effort */ }
  }

  useEffect(() => { refreshOnlineMatches(); }, [profile && profile.id]);

  useEffect(() => {
    if (['home', 'myprofile', 'leaderboard', 'player-detail', 'h2h'].includes(view)) {
      refreshOnlineMatches();
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [view]);

  const combinedMatchLog = useMemo(() => [...matchLog, ...onlineMatches], [matchLog, onlineMatches]);

  const [fpState, setFpState] = useState({ mode: 'enkel', bestOf: 5, names: ['', ''] });
  const [tState, setTState] = useState({ mode: 'enkel', count: 8, names: Array(8).fill(''), rounds: null });

  useEffect(() => {
    let cancelled = false;
    (async () => {
      try {
        const s = await window.storage.get('settings', false);
        if (!cancelled && s && s.value) setSettings(prev => ({ ...prev, ...JSON.parse(s.value) }));
      } catch (e) { /* no settings yet */ }
      try {
        const m = await window.storage.get('matchLog', false);
        if (!cancelled && m && m.value) setMatchLog(JSON.parse(m.value));
      } catch (e) { /* no history yet */ }
      try {
        const l = await window.storage.get('lang', false);
        if (!cancelled && l && l.value) setLangState(l.value);
      } catch (e) { /* no lang preference yet */ }
      try {
        const c = await window.storage.get('competition', false);
        if (!cancelled && c && c.value) setCompetitionState(JSON.parse(c.value));
      } catch (e) { /* no active competition yet */ }
      try {
        const f = await window.storage.get('friends', false);
        if (!cancelled && f && f.value) setFriendsState(JSON.parse(f.value));
      } catch (e) { /* no friends yet */ }
      if (!cancelled) setLoaded(true);
    })();
    return () => { cancelled = true; };
  }, []);

  function updateSettings(patch) {
    setSettings(prev => {
      const updated = { ...prev, ...patch };
      window.storage.set('settings', JSON.stringify(updated), false).catch(() => {});
      return updated;
    });
  }

  function setLang(code) {
    setLangState(code);
    window.storage.set('lang', code, false).catch(() => {});
  }

  function recordMatch(record) {
    setMatchLog(prev => {
      const updated = [record, ...prev].slice(0, 200);
      window.storage.set('matchLog', JSON.stringify(updated), false).catch(() => {});
      return updated;
    });
  }

  function setCompetition(updater) {
    setCompetitionState(prev => {
      const updated = typeof updater === 'function' ? updater(prev) : updater;
      if (updated === null) {
        window.storage.delete('competition', false).catch(() => {});
      } else {
        window.storage.set('competition', JSON.stringify(updated), false).catch(() => {});
      }
      return updated;
    });
  }

  function startCompetition(comp) {
    setCompetition(comp);
    setView('competition-play');
  }

  function selectPlayer(name, profileId) {
    setSelectedPlayer(name);
    setSelectedPlayerProfileId(profileId || null);
    setView('player-detail');
  }

  function selectGroup(id, name) {
    setSelectedGroupId(id);
    setSelectedGroupName(name || '');
    setView('group-detail');
  }

  function challengePlayer(opponentName, opponentProfileId) {
    const me = profile ? { profileId: profile.id, name: profile.username || '' } : null;
    const opponent = { profileId: opponentProfileId || null, name: opponentName };
    setFpState(s => ({ ...s, mode: 'enkel', presetParticipants: [me, opponent] }));
    setView('freeplay-setup');
  }

  function toggleFriend(name) {
    setFriendsState(prev => {
      const updated = prev.includes(name) ? prev.filter(n => n !== name) : [...prev, name];
      window.storage.set('friends', JSON.stringify(updated), false).catch(() => {});
      return updated;
    });
  }


  async function resetAllData() {
    try {
      const listing = await window.storage.list('', false);
      const keys = (listing && listing.keys) || [];
      await Promise.all(keys.map(k => window.storage.delete(k, false).catch(() => {})));
    } catch (e) { /* best effort wipe */ }
    setSettings({ coinToss: false, voice: false, setBreaks: true, pointSound: true, customSets: false });
    setMatchLog([]);
    setPhotos({});
    setFriendsState([]);
    setCompetitionState(null);
    setLangState('nl');
    setView('home');
  }

  const t = (key, vars) => tFn(lang, key, vars);
  const langCtxValue = { lang, setLang, t, languages: LANGUAGES };

  if (session === undefined) {
    return <div className="fixed inset-0 flex items-center justify-center" style={{ background: C.bg, color: C.dim }}>{t('loading_text')}</div>;
  }
  if (session === null) {
    return (
      <LangContext.Provider value={langCtxValue}>
        <style>{fontImport}</style>
        <AuthScreen />
      </LangContext.Provider>
    );
  }

  let content;
  if (!loaded) {
    content = <div className="tt-body text-center py-20" style={{ color: C.dim }}>{t('loading_text')}</div>;
  } else if (view === 'home') content = <Home matchLog={combinedMatchLog} />;
  else if (view === 'myprofile') content = <MyProfile setView={setView} matchLog={combinedMatchLog} session={session} profile={profile} setProfile={setProfile} />;
  else if (view === 'settings') content = <SettingsScreen setView={setView} settings={settings} updateSettings={updateSettings} resetAllData={resetAllData} />;
  else if (view === 'leaderboard') content = <Leaderboard setView={setView} matchLog={combinedMatchLog} photos={photos} setPhotos={setPhotos} onSelectPlayer={selectPlayer} friends={friends} profile={profile} />;
  else if (view === 'player-detail') content = <PlayerDetail setView={setView} playerName={selectedPlayer} playerProfileId={selectedPlayerProfileId} matchLog={combinedMatchLog} photos={photos} setPhotos={setPhotos} friends={friends} toggleFriend={toggleFriend} onChallenge={challengePlayer} profile={profile} />;
  else if (view === 'h2h') content = <HeadToHead setView={setView} matchLog={combinedMatchLog} photos={photos} setPhotos={setPhotos} profile={profile} />;
  else if (view === 'groups') content = <GroupsScreen setView={setView} session={session} onSelectGroup={selectGroup} profile={profile} />;
  else if (view === 'group-detail') content = <GroupDetailScreen setView={setView} groupId={selectedGroupId} groupName={selectedGroupName} session={session} matchLog={combinedMatchLog} onSelectPlayer={selectPlayer} />;
  else if (view === 'friends') content = <FriendsScreen setView={setView} session={session} onSelectPlayer={selectPlayer} />;
  else if (view === 'freeplay-setup') content = <FreePlaySetup setView={setView} state={fpState} setState={setFpState} session={session} settings={settings} />;
  else if (view === 'freeplay-play') content = <FreePlayPlay setView={setView} state={fpState} settings={settings} recordMatch={recordMatch} session={session} />;
  else if (view === 'competition-setup') content = <CompetitionSetup setView={setView} onStart={startCompetition} session={session} />;
  else if (view === 'competition-play') content = competition
    ? <CompetitionPlay setView={setView} competition={competition} setCompetition={setCompetition} settings={settings} recordMatch={recordMatch} session={session} />
    : <CompetitionSetup setView={setView} onStart={startCompetition} session={session} />;
  else if (view === 'tournament-setup') content = <TournamentSetup setView={setView} state={tState} setState={setTState} session={session} />;
  else if (view === 'tournament-play') content = <TournamentPlay setView={setView} state={tState} setState={setTState} settings={settings} recordMatch={recordMatch} session={session} />;

  return (
    <LangContext.Provider value={langCtxValue}>
      <div className="tt-body w-full flex" style={{ background: C.bg, minHeight: '100vh' }}>
        <style>{fontImport}</style>
        <Sidebar view={view} setView={setView} hasCompetition={!!competition} />
        {view === 'home' ? (
          <div className="flex-1" style={{ minHeight: '100vh' }}>
            {content}
          </div>
        ) : (
          <div className="flex-1 flex justify-center">
            <div className="w-full max-w-3xl p-4 sm:p-8">
              {content}
            </div>
          </div>
        )}
      </div>
    </LangContext.Provider>
  );
}
